const TableBody = ({
    data = [],
    columns = [],
    loading = false,
    colSpan,
    emptyMessage = 'Nessun elemento trovato',
    renderActions,
}) => {
    const effectiveColSpan = colSpan ?? columns.length + (renderActions ? 1 : 0);

    if (loading) {
        return (
            <tbody>
                <tr>
                    <td colSpan={effectiveColSpan} className="loading-cell">
                        <div className="loading-cell__inner">
                            <i className="fas fa-spinner fa-spin" />
                            <span>Caricamento...</span>
                        </div>
                    </td>
                </tr>
            </tbody>
        );
    }

    if (data.length === 0) {
        return (
            <tbody>
                <tr>
                    <td colSpan={effectiveColSpan} className="empty-cell">
                        {emptyMessage}
                    </td>
                </tr>
            </tbody>
        );
    }

    return (
        <tbody>
            {data.map((item) => (
                <tr key={item.id}>
                    {columns.map((col) => (
                        <td key={col.key} className={col.className}>
                            {col.render ? col.render(item) : item[col.key]}
                        </td>
                    ))}
                    {renderActions && (
                        <td className="actions-cell">
                            {renderActions(item)}
                        </td>
                    )}
                </tr>
            ))}
        </tbody>
    );
}

export default TableBody
