import { BaseService } from "./base.service";

export const ProfileService = {
    ...BaseService,

    basePath: '',

    // Ottieni il profilo dell'utente corrente
    getProfile: function () {
        return this.request({
            url: '/profile',
            type: 'get'
        });
    },

    // Aggiorna il profilo dell'utente
    updateProfile: function (data) {
        return this.request({
            url: '/profile',
            type: 'patch',
            body: data
        });
    },

    // Salva l'utente nel localStorage
    setUser: function (user) {
        localStorage.setItem('user', JSON.stringify(user));
    },

    // Aggiorna l'avatar
    updateAvatar: function (file) {
        const formData = new FormData();
        formData.append("avatar", file);
        return this.request({
            url: '/profile/avatar',
            type: 'post',
            body: formData
        });
    },

    // Ottieni tutte le sessioni di login
    getSessions: function () {
        return this.request({
            url: '/sessions',
            type: 'get'
        });
    },

    // Invalida una sessione specifica
    invalidateSession: function (sessionId) {
        return this.request({
            url: `/sessions/${sessionId}`,
            type: 'delete'
        });
    },

    // Invalida tutte le sessioni tranne quella corrente
    invalidateAllOtherSessions: function () {
        return this.request({
            url: '/sessions/others',
            type: 'delete'
        });
    }
};

