import { useState, useEffect, useCallback, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';

/**
 * Custom hook per gestire datatable con paginazione, sorting, ricerca e filtri
 * Sincronizza lo stato con i query params dell'URL
 *
 * @param {Object} config - Configurazione del datatable
 * @param {Function} config.fetchFn - Funzione che accetta i query params e restituisce una Promise ({ data: { data: [], total: number } })
 * @param {number} config.defaultPageSize - Numero di elementi per pagina di default (default: 10)
 * @param {string} config.defaultSortField - Campo di default per il sorting
 * @param {string} config.defaultSortOrder - Ordine di default ('asc' o 'desc')
 * @param {Array<number>} config.pageSizeOptions - Opzioni disponibili per elementi per pagina
 * @returns {Object} Stato e funzioni per gestire il datatable
 */
export const useDataTable = ({
    fetchFn,
    defaultPageSize = 10,
    defaultSortField = null,
    defaultSortOrder = 'asc',
    pageSizeOptions = [10, 25, 50, 100]
}) => {
    const [searchParams, setSearchParams] = useSearchParams();

    // Stati per i dati
    const [data, setData] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [totalItems, setTotalItems] = useState(0);

    // Leggi i parametri dai query params o usa i valori di default
    const page = useMemo(() => {
        const pageParam = searchParams.get('page');
        return pageParam ? parseInt(pageParam, 10) : 1;
    }, [searchParams]);

    const pageSize = useMemo(() => {
        const sizeParam = searchParams.get('per_page');
        return sizeParam ? parseInt(sizeParam, 10) : defaultPageSize;
    }, [searchParams, defaultPageSize]);

    const sortField = useMemo(() => {
        return searchParams.get('sort') || defaultSortField;
    }, [searchParams, defaultSortField]);

    const sortOrder = useMemo(() => {
        return searchParams.get('direction') || defaultSortOrder;
    }, [searchParams, defaultSortOrder]);

    const search = useMemo(() => {
        return searchParams.get('search') || '';
    }, [searchParams]);

    // Funzione per ottenere tutti i filtri custom (esclusi i parametri standard)
    const customFilters = useMemo(() => {
        const standardParams = ['page', 'per_page', 'sort', 'direction', 'search'];
        const filters = {};

        searchParams.forEach((value, key) => {
            if (!standardParams.includes(key)) {
                filters[key] = value;
            }
        });

        return filters;
    }, [searchParams]);

    // Funzione per aggiornare i query params (rimuove i valori di default per mantenerli puliti)
    const updateQueryParams = useCallback((updates) => {
        const newParams = new URLSearchParams(searchParams);

        Object.entries(updates).forEach(([key, value]) => {
            // Rimuovi il parametro se è il valore di default o è vuoto
            const shouldRemove =
                (key === 'page' && (value === 1 || value === '1')) ||
                (key === 'per_page' && value === defaultPageSize) ||
                (key === 'sort' && value === defaultSortField) ||
                (key === 'direction' && value === defaultSortOrder) ||
                (key === 'search' && !value) ||
                value === null ||
                value === undefined ||
                value === '';

            if (shouldRemove) {
                newParams.delete(key);
            } else {
                newParams.set(key, value);
            }
        });

        setSearchParams(newParams, { replace: true });
    }, [searchParams, setSearchParams, defaultPageSize, defaultSortField, defaultSortOrder]);

    // Funzioni per gestire le varie azioni
    const setPage = useCallback((newPage) => {
        updateQueryParams({ page: newPage });
    }, [updateQueryParams]);

    const setPageSize = useCallback((newSize) => {
        updateQueryParams({ per_page: newSize, page: 1 });
    }, [updateQueryParams]);

    const setSort = useCallback((field, order = 'asc') => {
        updateQueryParams({ sort: field, direction: order });
    }, [updateQueryParams]);

    const toggleSort = useCallback((field) => {
        if (sortField === field) {
            // Se è già il campo corrente, inverti l'ordine
            const newOrder = sortOrder === 'asc' ? 'desc' : 'asc';
            setSort(field, newOrder);
        } else {
            // Nuovo campo, usa l'ordine di default
            setSort(field, 'asc');
        }
    }, [sortField, sortOrder, setSort]);

    const setSearch = useCallback((searchValue) => {
        updateQueryParams({ search: searchValue, page: 1 });
    }, [updateQueryParams]);

    const setFilter = useCallback((filterKey, filterValue) => {
        updateQueryParams({ [filterKey]: filterValue, page: 1 });
    }, [updateQueryParams]);

    const removeFilter = useCallback((filterKey) => {
        const newParams = new URLSearchParams(searchParams);
        newParams.delete(filterKey);
        setSearchParams(newParams, { replace: true });
    }, [searchParams, setSearchParams]);

    const clearAllFilters = useCallback(() => {
        setSearchParams(new URLSearchParams(), { replace: true });
    }, [setSearchParams]);

    // Applica search + filtri custom in un'unica operazione (evita sovrascritture da chiamate multiple)
    const applyFilters = useCallback(({ search: searchValue, set: filtersToSet = {}, remove: filtersToRemove = [] }) => {
        const newParams = new URLSearchParams(searchParams);

        if (searchValue == null || searchValue === '') {
            newParams.delete('search');
        } else {
            newParams.set('search', searchValue);
        }

        Object.entries(filtersToSet).forEach(([key, value]) => newParams.set(key, value));
        filtersToRemove.forEach((key) => newParams.delete(key));

        newParams.delete('page');
        setSearchParams(newParams, { replace: true });
    }, [searchParams, setSearchParams]);

    // Restituisce i queryParams da passare all'endpoint
    const buildParams = useMemo(() => {
        return Object.fromEntries(searchParams);
    }, [searchParams]);

    // Fetch dei dati
    const fetchData = useCallback(async () => {
        setLoading(true);
        setError(null);

        try {
            const { data: resData } = await fetchFn(buildParams);

            // Assumiamo che il backend ritorni { data: [...], total: number }
            setData(resData?.data || []);
            setTotalItems(resData?.total || 0);
        } catch (err) {
            setError(err.message);
            setData([]);
            setTotalItems(0);
        } finally {
            setLoading(false);
        }
    }, [buildParams]);

    // Effettua il fetch quando cambiano i parametri
    useEffect(() => {
        fetchData();
    }, [fetchData]);

    // Calcola le informazioni di paginazione
    const totalPages = Math.ceil(totalItems / pageSize);
    const hasNextPage = page < totalPages;
    const hasPrevPage = page > 1;
    const startItem = totalItems === 0 ? 0 : (page - 1) * pageSize + 1;
    const endItem = Math.min(page * pageSize, totalItems);

    return {
        // Dati
        data,
        loading,
        error,
        totalItems,

        // Paginazione
        page,
        pageSize,
        totalPages,
        hasNextPage,
        hasPrevPage,
        startItem,
        endItem,
        pageSizeOptions,
        setPage,
        setPageSize,
        goToNextPage: () => hasNextPage && setPage(page + 1),
        goToPrevPage: () => hasPrevPage && setPage(page - 1),
        goToFirstPage: () => setPage(1),
        goToLastPage: () => setPage(totalPages),

        // Sorting
        sortField,
        sortOrder,
        setSort,
        toggleSort,

        // Ricerca
        search,
        setSearch,

        // Filtri
        customFilters,
        setFilter,
        removeFilter,
        clearAllFilters,

        // Utility
        refetch: fetchData,
        buildParams,
        setData,
        applyFilters
    };
};

export default useDataTable;
