import React, { useEffect, useMemo, useState } from 'react';
import { Modal, Button } from 'react-bootstrap';
import { formatDate } from '../../utils/date';
import SetTracker from './components/SetTracker';

const CardEsercizio = ({
    saveSessionItemCb = () => { },
    esercizio = {},
    exerciseSessions = [],
    handleChangeSessions = () => { },
    handleAddRow = () => { },
    handleChangeNote,
    saveChangedNote,
    setCurrentVideo,
    setTimer,
    startedSessionInfo = null }) => {
    const [showModalSession, setShowModalSession] = useState(false);
    const numeroSerie = parseInt(esercizio?.serieTotali) || 4;
    const [setsData, setSetsData] = useState(null);
    const [currentActiveSet, setCurrentActiveSet] = useState(0);
    const [pendingSave, setPendingSave] = useState(null);

    // Aggiornamento dei valori del set peso|reps
    const handleUpdateSet = (setNumber, inputTarget, value) => {
        const parseValue = value < 0 ? 0 : value;

        setSetsData(prev => {
            return {
                ...prev,
                sets: prev.sets.map(set => set.setNumber === setNumber ? { ...set, [inputTarget]: parseValue } : set)
            }
        });
    }

    // Invio il gruppo di sets dell'esercizio al backend
    // ? nota: pure se clicco "salva" sulla singola riga set, in realtà sto inviando al server tutte le righe sets dell'esercizio
    const handleSaveSet = () => {
        const setsDataMapped = {
            session_id: setsData.session_id,
            protocol_exercise_id: setsData.protocol_exercise_id,
            exercise_id: setsData.exercise_id,
            reps: setsData.sets.map(item => item.actualReps),
            weights: setsData.sets.map(item => item.actualWeight),
            is_completed: setsData.sets.every(set => set.isCompleted),
        }

        saveSessionItemCb(esercizio, setsDataMapped);
    }

    // Quando setto come completo un sets...
    const handleToggleSetComplete = (setNumber) => {
        setSetsData(prev => {
            const newSets = {
                ...prev,
                sets: prev.sets.map(set => set.setNumber === setNumber ? { ...set, isCompleted: true } : set)
            }

            // Trova prossima serie non completata
            const nextIncompleteSet = newSets.sets.findIndex(set => !set.isCompleted);
            setCurrentActiveSet(nextIncompleteSet !== -1 ? nextIncompleteSet : newSets.sets.length - 1);

            // Se tutti i sets sono stati completati, segno l'esercizio come completato
            const allCompleted = newSets.sets.every(set => set.isCompleted);
            if (allCompleted) {
                const sData = {
                    session_id: newSets.session_id,
                    protocol_exercise_id: newSets.protocol_exercise_id,
                    exercise_id: newSets.exercise_id,
                    reps: newSets.sets.map(item => item.actualReps),
                    weights: newSets.sets.map(item => item.actualWeight),
                    is_completed: allCompleted
                }

                // Non chiama direttamente il backend, ma salvo il payload della request in uno state locale
                setPendingSave({ esercizio, sData });
            }

            return newSets;
        });
    };

    // Memoizza sessionActive basandoti solo sulle proprietà che ti interessano
    const memoizedSessionActive = useMemo(() => {
        if (!startedSessionInfo) return null;

        return {
            ...startedSessionInfo
        };
    }, [startedSessionInfo?.id]);

    /**
     * Mostra nella modale "Storico sets" le sessioni esercizio passate
     * in ordine inverso (più recente prima)
     * Esclude la sessione attiva in corso (se esiste)
     * Uso useMemo per evitare ricalcoli inutili ad ogni render
     */
    const sessionsReversed = useMemo(() => {
        return exerciseSessions.slice().reverse().filter(s => s.session_id !== startedSessionInfo?.id);
    }, [exerciseSessions, startedSessionInfo?.id]);

    // Inizializzazione dei sets della sessione corrente
    useEffect(() => {
        if (!memoizedSessionActive) return;

        // La sessione appena inizializzata (iniziata)
        const currentSession = exerciseSessions.find(s => s.session_id === memoizedSessionActive.id);
        if (!currentSession) return;

        const actualReps = currentSession?.reps || [];
        const actualWeights = currentSession?.weights || [];

        // Ultima valida da dove voglio recuperare i dati di confronto
        const latestSession = exerciseSessions.filter(session => session.session_id !== memoizedSessionActive.id).pop();
        const repsTarget = latestSession?.reps || [];
        const weightsTarget = latestSession?.weights || [];

        // dati necessari per il set
        const data = Array.from({ length: parseInt(esercizio?.serieTotali) || 4 }, (_, i) => ({
            setNumber: i + 1,
            targetReps: repsTarget[i] || 1,
            targetWeight: weightsTarget[i] || 1,
            /* actualReps: null,
            actualWeight: null, */
            actualReps: actualReps[i] || repsTarget[i] || 1,
            actualWeight: actualWeights[i] || weightsTarget[i] || 1,
            isCompleted: currentSession.is_completed || false
        }))

        setSetsData({
            // per ogni set aggiungo pure i dati per il salvataggio al backend (non è proprio il massimo ma funziona!)
            session_id: memoizedSessionActive.id,
            exercise_id: currentSession.exercise_id,
            protocol_exercise_id: currentSession.protocol_exercise_id,
            sets: data
        });
    }, [memoizedSessionActive]);

    // Se c'è una chiamata asincrona per aggiornare una sessione esercizio in pending...
    useEffect(() => {
        if (pendingSave) {
            saveSessionItemCb(pendingSave.esercizio, pendingSave.sData);
            setPendingSave(null); // Reset per evitare chiamate multiple
        }
    }, [pendingSave, saveSessionItemCb]);

    return (
        <div className="card card-esercizio">
            <div className="card-body">
                <div className="d-flex justify-content-between specs-wrapper">
                    <div className="d-flex flex-column align-items-center">
                        <div className="ico-box">
                            <i className="fa-solid fa-dumbbell"></i>
                        </div>
                        <p className="specs-title">
                            {esercizio.serieTotali ?? 'ND'}
                            <span>Sets</span>
                        </p>
                        <p className="specs-sub-title">Complessivi</p>
                    </div>

                    <div className="d-flex flex-column align-items-center">
                        <div className="ico-box">
                            <i className="fa-solid fa-rotate-left"></i>
                        </div>
                        <p className="specs-title">
                            {esercizio.numeroRipetizioni}</p>
                        <p className="specs-sub-title">Ripetizioni</p>
                    </div>

                    <div className="d-flex flex-column align-items-center">
                        <div style={{ cursor: 'pointer' }} className="ico-box" onClick={() => setTimer(prev => ({ ...prev, isVisible: true, seconds: parseInt(esercizio.recuperoXserie) || 60 }))}
                        >
                            <i className="fa-solid fa-stopwatch"></i>
                        </div>
                        <p className="specs-title">
                            {esercizio.recuperoXserie ?? '60'}<span>sec</span>
                        </p>
                        <p className="specs-sub-title">Recupero</p>
                    </div>
                </div>
                <div className="form-note mb-3">
                    <label htmlFor="note">Note:</label>
                    <input type="text" placeholder="Inserisci note esercizio"
                        onChange={handleChangeNote}
                        onBlur={saveChangedNote}
                        value={esercizio.noteEsercizio || ""} />
                </div>

                <div className="section-weights d-flex align-items-center">
                    {!!setsData && <p className="mb-0"><i className="fa-solid fa-bullseye me-1"></i>Tracciamento Sets</p>}
                    <button className="btn ms-auto" onClick={() => setShowModalSession(true)}>
                        <i className="fas fa-chart-line me-1"></i>Storico sets
                    </button>
                </div>

                {/* Qui mostro info riguardo la sessione corrente */}
                {!!setsData && (
                    <div className="current-session-wrapper">
                        {setsData.sets.map((setData, index) => (
                            <SetTracker
                                key={setData.setNumber}
                                setNumber={setData.setNumber}
                                targetReps={setData.targetReps}
                                targetWeight={setData.targetWeight}
                                actualReps={setData.actualReps}
                                actualWeight={setData.actualWeight}
                                isCompleted={setData.isCompleted}
                                isActive={index === currentActiveSet}
                                handleUpdateSet={handleUpdateSet}
                                handleSaveSet={handleSaveSet}
                                onToggleComplete={handleToggleSetComplete}
                            />
                        ))}
                    </div>
                )}
            </div>

            {!!esercizio.videoEsecuzione && (
                <div className="card-footer">
                    <div className="d-flex flex-column gap-2">
                        {/* Lo attiveremo nella prossima versione */}
                        {/* <Button
                        variant="outline-primary"
                        disabled={true}>
                        <i className="fas fa-chart-line me-1"></i>
                        Visualizza Grafico
                    </Button> */}

                        <button className="btn btn-primary"
                            onClick={() => setCurrentVideo(esercizio.videoEsecuzione)}
                        >
                            <i className="fas fa-play-circle me-1"></i>
                            Guarda esecuzione
                        </button>
                    </div>
                </div>
            )}

            <Modal
                show={showModalSession}
                onHide={() => setShowModalSession(false)}
                centered
                size="lg"
            >
                <Modal.Header closeButton>
                    <Modal.Title>{esercizio?.nome}</Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    {!!sessionsReversed.length ?
                        <div className="modal-sessions-container">
                            {
                                sessionsReversed.map((session, i) => (
                                    <div className="mb-5" key={i}>
                                        <div className="d-flex justify-content-between">
                                            <p className="mb-0"><i className="fs-4 fa-regular fa-calendar-days me-2"></i>{formatDate(session?.session_date)}</p>
                                            <p className="mb-0">{session?.start_time}</p>
                                            <p className="mb-0">{session?.end_time}</p>
                                        </div>
                                        <div className="exercise-session-wp heading d-flex gap-2">
                                            <div className="child"></div>
                                            <div className="child">Peso (Kg)</div>
                                            <div className="child">Ripetizioni</div>
                                        </div>
                                        <div>
                                            {
                                                session.weights.map((peso, index) => (
                                                    <div className="exercise-session-wp d-flex gap-2" key={index}>
                                                        <div className="child">{index + 1} {esercizio?.hasMultipleMiniSet ? 'Mini-set' : 'Set'}</div>
                                                        <div className="child">
                                                            <input
                                                                type="number"
                                                                value={peso || ""}
                                                                onChange={(e) => handleChangeSessions("weights", esercizio.id, session.session_id, index, parseFloat(e.target.value))}
                                                                onBlur={() => saveSessionItemCb(esercizio, session)}
                                                            />
                                                        </div>
                                                        <div className="child">
                                                            <input
                                                                type="number"
                                                                value={session.reps?.[index] || ""}
                                                                onChange={(e) => handleChangeSessions("reps", esercizio.id, session.session_id, index, parseInt(e.target.value))}
                                                                onBlur={() => saveSessionItemCb(esercizio, session)}
                                                            />
                                                        </div>
                                                    </div>
                                                ))
                                            }</div>
                                        <div className="d-flex">
                                            <button className="add-row-btn btn btn-lg mx-auto" onClick={() => handleAddRow(esercizio.id, numeroSerie, session.session_id)} disabled={session.weights.length >= numeroSerie}>
                                                <i className="fa-solid fa-circle-plus"></i>
                                            </button>
                                        </div>
                                    </div>
                                ))
                            }
                        </div> : <></>
                    }
                </Modal.Body>
                <Modal.Footer>
                    <div className="d-flex w-100">
                        <Button
                            variant="outline-primary"
                            size="sm"
                            className="mx-auto"
                            disabled={true}
                        >
                            <i className="fas fa-chart-line me-1"></i>
                            Visualizza Grafico
                        </Button>
                    </div>
                </Modal.Footer>
            </Modal>
        </div>
    )
}

export default CardEsercizio
