import React, { useState, useEffect } from 'react'
import { Link, useNavigate, useSearchParams } from 'react-router-dom'
import AuthLayout from '../../components/AuthLayout';
import { InputError } from '../../components/FormComponents'
//import { SiteBackNavigate } from '../../components/SiteBackNavigate'
import { useValidationSystem } from '../../hooks/useValidationSystem';
import { useDispatch, useSelector } from "react-redux";
import { loginUser } from '../../features/user/userSlice'
import { toast } from 'react-toastify'

export const Login = () => {
    const navigate = useNavigate();
    const dispatch = useDispatch();
    const [searchParams] = useSearchParams();
    const { token, errors: loginErrors } = useSelector((state) => state.user);
    const { loading } = useSelector((state) => state.loader);
    const [passwordVisible, setPasswordVisible] = useState(false);
    const isDemo = searchParams.get("demo") === "true";

    // Credenziali demo
    const demoCredentials = {
        email: process.env.REACT_APP_DEMO_EMAIL || 'demo@workoutapp.com',
        password: process.env.REACT_APP_DEMO_PASSWORD || 'demo123'
    };
    // Regole per una prima validazione client side
    const validations = [
        {
            name: 'email',
            required: true,
            extra: 'email'
        },
        {
            name: 'password',
            required: true,
            extra: 'password'
        },
    ];

    const [data, dataToSend, setData, errors, setErrors, validate] = useValidationSystem({ initState: {}, validations });

    const onInputHandler = (e) => {
        e.preventDefault();
        const { name, value } = e.target;
        setData((prev) => ({ ...prev, [name]: value }));
    };
    const onSubmitHandler = (e) => {
        e.preventDefault();
        //Se la validazione va a buon fine..
        if (!validate()) return;

        //Eseguo il login..
        dispatch(loginUser(dataToSend));
    };

    // useEffect per aggiornare `error` quando cambia `loginError`
    useEffect(() => {
        if (loginErrors.password) {
            setErrors({ 'email': loginErrors.password, 'password': loginErrors.password });
        } else {
            toast.error(loginErrors.message);
        }
    }, [loginErrors]);

    useEffect(() => {
        if (!!token) navigate('/workouts/last');
    }, [token]);

    useEffect(() => {
        if (!isDemo) return;

        let emailIndex = 0;
        let passwordIndex = 0;

        const typeEmail = setInterval(() => {
            setData(prev => ({ ...prev, email: demoCredentials.email.substring(0, emailIndex) }));
            emailIndex++;
            if (emailIndex === demoCredentials.email.length) {
                clearInterval(typeEmail);

                // Dopo l’email, digita la password
                const typePassword = setInterval(() => {
                    setData(prev => ({ ...prev, password: demoCredentials.password.substring(0, passwordIndex) }));
                    passwordIndex++;
                    if (passwordIndex === demoCredentials.password.length) {
                        clearInterval(typePassword);
                    }
                }, 80);
            }
        }, 70);

        return () => {
            clearInterval(typeEmail);
        };
    }, [isDemo]);

    return (
        <AuthLayout>
            <div className="card-auth">
                <div className="logo"></div>
                {/* <img className="logo" src="logo.svg"> */}
                <h2>Login</h2>
                <h3>Let's go!</h3>
                <form className="form">
                    <div>
                        <div className="input-box">
                            <i className="fa-regular fa-user-circle"></i>
                            <input name="email" type="email"
                                placeholder="Inserisci la tua e-mail" autoComplete="email"
                                value={data.email ?? ''} onChange={onInputHandler} />
                        </div>
                        <InputError error={errors.email} />
                    </div>

                    <div>
                        <div className="input-box">
                            <i className="fa-solid fa-lock"></i>
                            <input name="password"
                                type={passwordVisible ? "text" : "password"}
                                placeholder="Inserisci la tua password"
                                autoComplete='new-password' value={data.password ?? ""}
                                onChange={onInputHandler} />

                            <button
                                type="button"
                                onClick={() => setPasswordVisible(!passwordVisible)}
                                className="btn-toggle-password"
                            >
                                <i className={passwordVisible ? "fas fa-eye" : "fas fa-eye-slash"}></i>
                            </button>
                        </div>
                        <InputError error={errors.password} />
                    </div>
                    <button className="submit" onClick={onSubmitHandler} disabled={loading}>
                        {loading ? (
                            <i className="fa fa-spinner fa-spin"></i>  // Spinner quando è in caricamento
                        ) : (
                            "Login"  // Testo del bottone quando non è in caricamento
                        )}
                    </button>
                </form>
                <Link to='/password/reset'>Password dimenticata?</Link>
                <footer>Hai bisogno di un account? Registrati <Link to="/register">qui</Link></footer>
            </div>
        </AuthLayout>
    )
}