// Importo l'istanza custom di axios
import axios from '../http/http';

export const BaseService = {
    baseUrl: `${process.env.REACT_APP_BASE_URL}/api`,
    basePath: '',

    getUrl: function (path) {
        return this.baseUrl + this.basePath + path;
    },

    request: function ({ url = '', type = 'get', body = {}, params = {}, options }) {
        const requestType = type.toLowerCase();
        if (['get', 'delete'].includes(requestType)) return axios[requestType](this.getUrl(url), options);
        return axios[requestType](this.getUrl(url), body, { params }, options);
    },

    all: function ({ url = '', params }) {
        return axios.get(this.getUrl(url), { params });
    },

    create: function ({ url = '', data = null, params }) {
        return axios.post(`${this.getUrl(url)}`, data, { params });
    },

    read: function ({ url = '', id, options }) {
        if (!id) return axios.get(`${this.getUrl(url)}`, options);
        return axios.get(`${this.getUrl(url)}/${id}`, options);
    },

    update: function ({ url = '', id, data }) {
        if (!id) return axios.put(`${this.getUrl(url)}`, data);
        return axios.put(`${this.getUrl(url)}/${id}`, data);
    },

    delete: function (id) {
        return axios.delete(`${this.getUrl('')}/${id}`);
    }
};