import { BaseService } from "./base.service";
import { TokenService } from "./token.service";

export const AuthService = {
    ...BaseService,
    ...TokenService,

    login: function (data) {
        return this.request({
            url: '/login',
            type: 'post',
            body: data
        });
    },

    loginByPhone: function (data) {
        return this.request({
            url: '/login/phone',
            type: 'post',
            body: data
        });
    },

    register: function (data) {
        return this.request({
            url: '/register',
            type: 'post',
            body: data
        });
    },

    logout: function () {
        return this.request({
            url: '/logout',
            type: 'delete',
        });
    },

    setUser: function (data) {
        this.setToken({ token: `Bearer ${data.access_token}` });
        localStorage.setItem('user', JSON.stringify(data.user));
    },

    getUser: function () {
        let user = null;

        try {
            user = JSON.parse(localStorage.getItem("user"));
        } catch (error) { }
        const token = this.getToken() || null;

        return {
            user,
            token
        };
    },
};