import TableHead from './TableHead';
import TableBody from './TableBody';
import TablePagination from './TablePagination';
import ItemStats from './ItemStats';

const DataTable = ({
    // Colonne e dati
    columns = [],
    data = [],
    loading = false,
    emptyMessage,
    tableClassName,

    // Azioni
    showActions = false,
    renderActions,

    // Sorting
    sortField,
    sortOrder,
    toggleSort,

    // Stats
    startItem,
    endItem,
    totalItems,
    pageSize,
    setPageSize,
    pageSizeOptions,

    // Paginazione
    page,
    totalPages,
    setPage,
    goToPrevPage,
    goToNextPage,
}) => (
    <div className="app-datatable">
        <ItemStats {...{ startItem, endItem, totalItems, pageSize, setPageSize, pageSizeOptions }} />

        <div className="table-wrapper">
            <table className={tableClassName}>
                <TableHead
                    columns={columns}
                    sortField={sortField}
                    sortOrder={sortOrder}
                    toggleSort={toggleSort}
                    showActions={showActions}
                />
                <TableBody
                    data={data}
                    columns={columns}
                    loading={loading}
                    emptyMessage={emptyMessage}
                    renderActions={renderActions}
                />
            </table>
        </div>

        <TablePagination {...{ page, totalPages, loading, goToPrevPage, goToNextPage, setPage }} />
    </div>
);

export default DataTable;
