import { BaseService } from "./base.service";

export const ExercisesService = {
    ...BaseService,

    basePath: '/exercises',

    // Ottiene tutti gli esercizi con filtri, sort e paginazione
    getAll: function (params = {}) {
        return this.all({
            url: '',
            params
        });
    },

    // Ottiene un esercizio specifico
    // Todo metodo non attivo nel backend, da implementare se necessario
    // getById: function (id) {
    //     return this.read({
    //         url: '',
    //         id
    //     });
    // },

    // Crea un nuovo esercizio
    createExercise: function (data) {
        return this.create({
            url: '',
            data
        });
    },

    // Aggiorna un esercizio
    updateExercise: function (id, data) {
        return this.update({
            url: '',
            id,
            data
        });
    },

    // Elimina un esercizio
    deleteExercise: function (id) {
        return this.delete(id);
    }
};
