import { useSelector } from 'react-redux';

/**
 * Hook personalizzato per gestire l'autenticazione e autorizzazione
 * Centralizza la logica di controllo accessi usando Redux
 */
export const useAuth = () => {
    const { user, token } = useSelector((state) => state.user);

    /**
     * Verifica se l'utente è autenticato
     * @returns {boolean}
     */
    const isAuthenticated = () => {
        return !!token;
    };

    /**
     * Verifica se l'utente è admin (tipoUtente = 3)
     * @returns {boolean}
     */
    const isAdmin = () => {
        return !!user && user.tipoUtente === 3;
    };

    /**
     * Verifica se l'utente ha un determinato tipo
     * @param {number} tipoUtente - Il tipo utente da verificare
     * @returns {boolean}
     */
    const hasUserType = (tipoUtente) => {
        return !!user && user.tipoUtente === tipoUtente;
    };

    /**
     * Verifica se l'utente può accedere a una risorsa admin
     * @returns {boolean}
     */
    const canAccessAdmin = () => {
        return isAuthenticated() && isAdmin();
    };

    return {
        user,
        token,
        isAuthenticated: isAuthenticated(),
        isAdmin: isAdmin(),
        canAccessAdmin: canAccessAdmin(),
        hasUserType
    };
};
