import { BaseService } from "./base.service";

export const SchedaService = {
    ...BaseService,

    basePath: '/workouts',

    createScheda: function (data) {
        return this.create({
            url: "/store",
            data
        });
    },

    allUser: function () {
        return this.all({ url: "" });
    },

    last: function () {
        return this.request({
            url: '/last',
            type: 'get',
        });
    },

    updateNote: function ({ id, value }) {
        return this.request({
            url: `/esercizio/${id}/update-note`,
            type: 'patch',
            body: {
                noteEsercizio: value
            }
        });
    },

    startSession: function ({ workoutId, data }) {
        return this.request({
            url: `/${workoutId}/session/start`,
            type: 'post',
            body: { ...data }
        });
    },

    stopSession: function ({ workoutId, data }) {
        return this.request({
            url: `/${workoutId}/session/stop`,
            type: 'post',
            body: { ...data }
        });
    },

    saveSession: function ({ workoutId, sessionId, data }) {
        return this.request({
            url: `/${workoutId}/session/${sessionId}/save`,
            type: 'post',
            body: { ...data }
        });
    },

    markExerciseCompleted: function ({ workoutId, sessionId, exerciseId }) {
        return this.request({
            url: `/${workoutId}/session/${sessionId}/exercise/${exerciseId}/complete`,
            type: 'post',
            body: {}
        });
    },

    /**
     * Salva il workout e le relative sessioni
     */
    setScheda: function (data) {
        localStorage.setItem('workout', JSON.stringify(data));
    },

    getLatestWorkout: function () {
        const data = localStorage.getItem('workout');
        try {
            return JSON.parse(data);
        } catch (error) {
            return {};
        }
    },

    /**
     * Cancella il workout e le sessioni associate
     */
    clearWorkout: function () {
        localStorage.removeItem('workout');
    }
};