import { useState, useEffect, useRef } from 'react';

const ActionsDropdown = ({ items = [] }) => {
    const [open, setOpen] = useState(false);
    const ref = useRef(null);

    useEffect(() => {
        const handleClickOutside = (e) => {
            if (ref.current && !ref.current.contains(e.target)) {
                setOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside, true);
        return () => document.removeEventListener('mousedown', handleClickOutside, true);
    }, []);

    return (
        <div className="actions-dropdown" ref={ref}>
            <button
                className="actions-dropdown__trigger"
                onClick={() => setOpen((prev) => !prev)}
                aria-haspopup="true"
                aria-expanded={open}
            >
                <i className="fas fa-ellipsis" />
            </button>

            {open && (
                <div className="actions-dropdown__menu">
                    {items.map((item, i) => (
                        <button
                            key={i}
                            className={`actions-dropdown__item${item.variant ? ` actions-dropdown__item--${item.variant}` : ''}`}
                            onClick={() => { item.onClick(); setOpen(false); }}
                        >
                            {item.icon && <i className={`${item.icon} me-2`} />}
                            {item.label}
                        </button>
                    ))}
                </div>
            )}
        </div>
    );
};

export default ActionsDropdown;
