import { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import { ExercisesService } from '../services/exercises.service';
import { hideLoader, showLoader } from '../features/loader/loaderSlice';
import { useValidationSystem } from './useValidationSystem';

const initState = {
    name: '',
    muscle_group_id: '',
    video_execution: ''
};

const validations = [
    { name: 'name', required: true, min: 2, max: 255 },
    { name: 'muscle_group_id', required: true },
    { name: 'video_execution', required: false }
];

export const useEserciziModal = ({ setExercises }) => {
    const dispatch = useDispatch();
    const { loading } = useSelector((state) => state.loader);

    const [showModal, setShowModal] = useState(false);
    const [selectedExerciseId, setSelectedExerciseId] = useState(null);

    const [formData, dataToSend, setFormData, formErrors, setFormErrors, validate] = useValidationSystem({
        initState,
        validations
    });

    const handleOpenModal = (exercise = null) => {
        if (exercise) {
            setSelectedExerciseId(exercise?.id);
            // Inizializza il form con i dati dell'esercizio in modifica
            setFormData({
                name: exercise?.name || '',
                muscle_group_id: exercise?.muscle_group_id || '',
                video_execution: exercise?.video_execution || ''
            });
        }
        setShowModal(true);
    };

    const handleCloseModal = () => {
        setShowModal(false);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!validate()) {
            return;
        }

        dispatch(showLoader());
        try {
            if (selectedExerciseId) {
                const { data } = await ExercisesService.updateExercise(selectedExerciseId, dataToSend);
                toast.success(data?.message ?? 'Esercizio aggiornato con successo');

                if (!!data?.data && setExercises) {
                    setExercises(prev => prev.map(ex => ex.id === data.data.id ? data.data : ex));
                }
            } else {
                const { data } = await ExercisesService.createExercise(dataToSend);
                toast.success(data?.message ?? 'Esercizio creato con successo');

                if (!!data?.data && setExercises) {
                    setExercises(prev => [data.data, ...prev]);
                }
            }

            handleCloseModal();
        } catch (error) {
            const errorData = error.response?.data;
            if (errorData?.errors) {
                setFormErrors(errorData.errors);
            } else {
                toast.error(errorData?.message ?? 'Errore nel salvataggio dell\'esercizio');

                if (errorData?.status_code === 404) {
                    if (selectedExerciseId && setExercises) {
                        setExercises(prev => prev.filter(ex => ex.id !== selectedExerciseId));
                    }
                    handleCloseModal();
                }
            }
        } finally {
            dispatch(hideLoader());
        }
    };


    // Reset del form alla chiusura della modale
    useEffect(() => {
        if (!showModal) {
            setFormData(initState);
            setFormErrors({});
            setSelectedExerciseId(null);
        }
    }, [showModal]);

    return {
        showModal,
        isEditing: !!selectedExerciseId,
        formData,
        formErrors,
        setFormData,
        loading,
        handleOpenModal,
        handleCloseModal,
        handleSubmit
    };
};
