import React, { useEffect, useState } from 'react';
import useDataTable from '../hooks/useDataTable';
import BaseLayout from '../components/BaseLayout';
import PageHeader from '../components/PageHeader';
import { Alert, Badge, Button, Card } from 'react-bootstrap';
import { ExercisesService } from '../services/exercises.service';
import ExercisesFilters from '../components/ExercisesFilters';
import { hideLoader, showLoader } from '../features/loader/loaderSlice';
import { MuscleGroupsService } from '../services/muscleGroups.service';
import { toast } from 'react-toastify';
import { useDispatch } from 'react-redux';
import DataTable from '../components/Datatable/DataTable';
import ActionsDropdown from '../components/ActionsDropdown';
import { useEserciziModal } from '../hooks/useEserciziModal';
import ExerciseFormModal from '../components/ExerciseFormModal';

const ExercisesTable = () => {
    const {
        // Dati
        data: exercises,
        loading,
        error,
        totalItems,

        // Paginazione
        page,
        pageSize,
        totalPages,
        startItem,
        endItem,
        pageSizeOptions,
        setPage,
        setPageSize,
        goToNextPage,
        goToPrevPage,

        // Sorting
        sortField,
        sortOrder,
        toggleSort,

        // Ricerca
        search,

        // Filtri custom
        customFilters,

        // Aggiornamento del datatable
        setData: setExercises,
        applyFilters
    } = useDataTable({
        fetchFn: (params) => ExercisesService.getAll(params),
        defaultPageSize: 15,
        defaultSortField: 'name',
        defaultSortOrder: 'asc',
        pageSizeOptions: [15, 25, 50, 100]
    });

    const { showModal, isEditing, formData, formErrors, setFormData, loading: exerciseLoading, handleOpenModal, handleCloseModal, handleSubmit } =
        useEserciziModal({ setExercises });

    const dispatch = useDispatch();
    const [muscleGroups, setMuscleGroups] = useState();

    const renderVideoExecutionColumn = (exercise) => {
        if (exercise.video_execution) {
            return <a
                href={exercise.video_execution}
                target="_blank"
                rel="noopener noreferrer"
            >
                <i className="fas fa-video me-2"></i>
                Visualizza
            </a>
        } else {
            return <span className="text-muted">-</span>
        }
    }

    const columns = [
        { key: 'id', label: 'ID', sortable: true },
        { key: 'name', label: 'Nome', sortable: true },
        { key: 'muscle_group_name', label: 'Gruppo Muscolare', sortable: true, sortKey: 'muscle_group', render: (item) => (<Badge bg="primary">{item.muscle_group_name}</Badge>) },
        // { key: 'video_execution', label: 'Video Esecuzione', sortable: true, className: 'execution-cell', render: (item) => item.video_execution || '-' },
        { key: 'video_execution', label: 'Video Esecuzione', sortable: true, className: 'execution-cell', render: renderVideoExecutionColumn },
    ];

    const handleDelete = async (id) => {
        if (!window.confirm('Sei sicuro di voler eliminare questo esercizio?')) return;
        dispatch(showLoader());
        try {
            const { data } = await ExercisesService.deleteExercise(id);
            toast.success(data?.message || 'Esercizio eliminato con successo');
            setExercises(prev => prev.filter(ex => ex.id !== id));
        } catch (error) {
            toast.error(error.response?.data?.message || "Errore nell'eliminazione dell'esercizio");
        } finally {
            dispatch(hideLoader());
        }
    };

    // Load muscle groups once on mount
    useEffect(() => {
        const loadMuscleGroups = async () => {
            dispatch(showLoader());
            try {
                const { data } = await MuscleGroupsService.getAll();
                if (data?.result) setMuscleGroups(data.result);
            } catch {
                toast.error('Errore nel caricamento dei gruppi muscolari');
            } finally {
                dispatch(hideLoader());
            }
        };
        loadMuscleGroups();
    }, []);

    return (
        <BaseLayout>
            <div className="page-content exercises-table-page">
                <PageHeader
                    title="Gestione Esercizi"
                    subtitle="Visualizza e gestisci tutti gli esercizi disponibili in piattaforma"
                    actions={[
                        <Button
                            key="create"
                            variant="primary"
                            onClick={handleOpenModal}
                            className="btn-primary"
                        >
                            <i className="fas fa-plus me-2"></i>
                            Nuovo Esercizio
                        </Button>
                    ]}
                />

                {error && <Alert variant="danger" dismissible={true}>Errore nel caricamento dei dati: {error}</Alert>}

                <ExercisesFilters
                    {...{ muscleGroups, search, customFilters, applyFilters }}
                />

                <Card className="datatable-card">
                    <Card.Body>
                        <DataTable
                            columns={columns}
                            data={exercises}
                            loading={loading}
                            emptyMessage="Nessun esercizio trovato"
                            tableClassName="exercises-table"
                            showActions={true}
                            renderActions={(exercise) => (
                                <ActionsDropdown items={[
                                    { label: 'Modifica', icon: 'fas fa-pen', onClick: () => handleOpenModal(exercise) },
                                    { label: 'Elimina', icon: 'fas fa-trash', variant: 'danger', onClick: () => handleDelete(exercise.id) },
                                ]} />
                            )}
                            sortField={sortField}
                            sortOrder={sortOrder}
                            toggleSort={toggleSort}
                            startItem={startItem}
                            endItem={endItem}
                            totalItems={totalItems}
                            pageSize={pageSize}
                            setPageSize={setPageSize}
                            pageSizeOptions={pageSizeOptions}
                            page={page}
                            totalPages={totalPages}
                            setPage={setPage}
                            goToPrevPage={goToPrevPage}
                            goToNextPage={goToNextPage}
                        />
                    </Card.Body>
                </Card>

                <ExerciseFormModal
                    show={showModal}
                    isEditing={isEditing}
                    formData={formData}
                    formErrors={formErrors}
                    setFormData={setFormData}
                    loading={exerciseLoading}
                    muscleGroups={muscleGroups}
                    onClose={handleCloseModal}
                    onSubmit={handleSubmit}
                />
            </div>
        </BaseLayout>
    );
};

export default ExercisesTable;
