import React from 'react';

const ChartControls = ({ chartType, onChartTypeChange }) => {
    const chartTypes = [
        { type: 'combined', icon: 'fa-chart-line', title: 'Vista combinata' },
        { type: 'weight', icon: 'fa-weight', title: 'Solo pesi' },
        { type: 'reps', icon: 'fa-redo', title: 'Solo ripetizioni' },
        { type: 'volume', icon: 'fa-cube', title: 'Volume totale' }
    ];

    return (
        <div className="chart-controls">
            {chartTypes.map(({ type, icon, title }) => (
                <button
                    key={type}
                    className={`chart-btn ${chartType === type ? 'active' : ''}`}
                    onClick={() => onChartTypeChange(type)}
                    title={title}
                >
                    <i className={`fas ${icon}`}></i>
                </button>
            ))}
        </div>
    );
};

export default ChartControls;
