import React, { useEffect, useState } from 'react';
import { Card, Button, Badge, Modal } from 'react-bootstrap';
import { useSelector, useDispatch } from 'react-redux';
import { toast } from 'react-toastify';
import BaseLayout from '../components/BaseLayout';
import { Input, Select } from '../components/FormComponents';
import { ProfileService } from '../services/profile.service';
import { hideLoader, showLoader } from '../features/loader/loaderSlice';
import { updateUser, fetchProfile, fetchSessions, removeSession, removeAllOtherSessions, updateAvatar } from '../features/user/userSlice';
import { formatDate } from '../utils/date';
import { useValidationSystem } from '../hooks/useValidationSystem';
import { getUserInitials, getUserName } from '../functions';

const Profilo = () => {
    const dispatch = useDispatch();
    const { user, errors: userErrors, sessions, sessionsLoading } = useSelector(state => state.user);
    const { loading } = useSelector((state) => state.loader);
    const [isEditing, setIsEditing] = useState(false);
    const [avatarPreview, setAvatarPreview] = useState(null);
    const [showInvalidateModal, setShowInvalidateModal] = useState(false);
    const [sessionToInvalidate, setSessionToInvalidate] = useState(null);

    const initState = {
        username: '',
        email: '',
        nome: '',
        cognome: '',
        cellulare: '',
        data_nascita: '',
        sesso: ''
    };

    const validations = [
        {
            name: 'username',
            required: true,
            min: 3,
            max: 50
        },
        {
            name: 'email',
            required: true,
            extra: 'email'
        },
        {
            name: 'nome',
            required: false,
            max: 50
        },
        {
            name: 'cognome',
            required: false,
            max: 50
        },
        {
            name: 'cellulare',
            required: false,
            extra: 'phone'
        },
        {
            name: 'data_nascita',
            required: false
        },
        {
            name: 'sesso',
            required: false
        }
    ];

    const [data, dataToSend, setData, errors, setErrors, validate] = useValidationSystem({ initState, validations });

    const resetDefaultValuesUser = (userData) => {
        setData({
            username: userData.username,
            email: userData.email,
            nome: userData.nome || '',
            cognome: userData.cognome || '',
            cellulare: userData.cellulare || '',
            data_nascita: userData.data_nascita || '',
            sesso: userData.sesso || ''
        });
    }

    useEffect(() => {
        resetDefaultValuesUser(user);

        if (!!user.avatar_url) {
            setAvatarPreview(user.avatar_url);
        }
    }, [user, setData]);

    /* UseEffect sugli errori del form ricevuti dal backend */
    useEffect(() => {
        if (userErrors?.errors) {
            setErrors(userErrors.errors);
            if (userErrors.message) {
                toast.error(userErrors.message);
            }
        }
    }, [userErrors, setErrors]);

    const handleInputChange = (e) => {
        e.preventDefault();
        const { name, value } = e.target;
        setData((prev) => ({ ...prev, [name]: value }));
    };

    const handleAvatarChange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        // Validazione file
        if (!file.type.startsWith('image/')) {
            toast.error('Il file deve essere un\'immagine');
            return;
        }

        if (file.size > 10 * 1024 * 1024) {
            toast.error('L\'immagine non deve superare i 10MB');
            return;
        }

        // Preview
        const reader = new FileReader();
        reader.onloadend = () => {
            setAvatarPreview(reader.result);
        };
        reader.readAsDataURL(file);

        // Upload
        try {
            dispatch(showLoader());
            const { data } = await ProfileService.updateAvatar(file);

            toast.success(data.message);
            ProfileService.setUser(data.data);
            if (data.data.avatar_url) {
                setAvatarPreview(data.data.avatar_url);
                dispatch(updateAvatar(data.data.avatar_url));
            }
        } catch (error) {
            toast.error(error.response?.data?.message || 'Errore nell\'aggiornamento dell\'avatar');
        } finally {
            dispatch(hideLoader());
        }
    };

    const handleSaveProfile = async (e) => {
        e.preventDefault();
        if (!validate()) return;

        const resultAction = await dispatch(updateUser(dataToSend));
        if (updateUser.fulfilled.match(resultAction)) {
            setIsEditing(false);
            const { data, message } = resultAction.payload;
            toast.success(message);
            ProfileService.setUser(data);
        }
    };

    const handleCancelEdit = () => {
        // Ripristina il form ai valori originali del global state redux
        resetDefaultValuesUser(user);

        setIsEditing(false);
        setErrors({});
    };


    const handleInvalidateSession = async (sessionId) => {
        try {
            dispatch(showLoader());
            const { data } = await ProfileService.invalidateSession(sessionId);
            toast.success(data.message);
            dispatch(removeSession(sessionId));
            setShowInvalidateModal(false);
            setSessionToInvalidate(null);
        } catch (error) {
            toast.error(error.response?.data?.message || 'Errore nell\'invalidazione della sessione');
        } finally {
            dispatch(hideLoader());
        }
    };

    const handleInvalidateAllOthers = async () => {
        try {
            dispatch(showLoader());
            const { data } = await ProfileService.invalidateAllOtherSessions();
            toast.success(data.message);
            dispatch(removeAllOtherSessions());
        } catch (error) {
            toast.error(error.response?.data?.message || 'Errore nell\'invalidazione delle sessioni');
        } finally {
            dispatch(hideLoader());
        }
    };

    const openInvalidateModal = (session) => {
        setSessionToInvalidate(session);
        setShowInvalidateModal(true);
    };

    const handleReloadProfile = async () => {
        const resultAction = await dispatch(fetchProfile());
        if (fetchProfile.fulfilled.match(resultAction)) {
            const { message } = resultAction.payload;
            toast.success(message || 'Profilo ricaricato con successo');
        } else {
            toast.error('Errore nel ricaricamento del profilo');
        }
    };

    const formatDateTime = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleString('it-IT', {
            day: '2-digit',
            month: '2-digit',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    useEffect(() => {
        // Carica le sessioni solo se non sono già presenti nello state
        if (sessions.length === 0) {
            dispatch(fetchSessions());
        }
        document.title = "Il mio Profilo";
    }, [dispatch, sessions.length]);

    return (
        <BaseLayout>
            <div className="page-content">
                <div className="page-header">
                    <h1 className="page-header__title">Il mio Profilo</h1>
                    <p className="page-header__subtitle">Gestisci le tue informazioni personali e le sessioni attive</p>
                </div>

                {/* Sezione Avatar e Anagrafica */}
                <Card className="profile-page__card profile-page__card--primary mb-4">
                    <Card.Body className="position-relative">
                        <div className="profile-page__avatar-section">
                            <div className="profile-page__avatar-wrapper">
                                {avatarPreview ? (
                                    <img
                                        src={avatarPreview}
                                        alt="Avatar"
                                        className="profile-page__avatar"
                                    />
                                ) : (
                                    <div className="profile-page__avatar-placeholder">
                                        {getUserInitials(data)}
                                    </div>
                                )}
                                <label className="profile-page__avatar-upload">
                                    <input
                                        type="file"
                                        accept="image/*"
                                        onChange={handleAvatarChange}
                                        style={{ display: 'none' }}
                                    />
                                    <i className="fas fa-camera"></i>
                                </label>
                            </div>
                            <div className="profile-page__avatar-info">
                                <h3 className="profile-page__avatar-name">
                                    {getUserName(data)}
                                </h3>
                                <p className="profile-page__avatar-email">{data.email}</p>
                            </div>
                        </div>
                        <Button
                            variant="outline-primary"
                            onClick={handleReloadProfile}
                            disabled={loading}
                            size="sm"
                            className="position-absolute top-0 end-0 m-4"
                        >
                            {loading ? (
                                <i className="fa fa-spinner fa-spin"></i>
                            ) : (
                                <i className="fas fa-sync-alt"></i>
                            )}
                        </Button>

                        <div className="profile-page__form-section">
                            {!isEditing ? (
                                <div className="profile-page__info-grid">
                                    <div className="profile-page__info-item">
                                        <label>Username</label>
                                        <p>{data?.username || '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Email</label>
                                        <p>{data?.email || '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Nome</label>
                                        <p>{data.nome || '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Cognome</label>
                                        <p>{data.cognome || '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Cellulare</label>
                                        <p>{data.cellulare || '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Data di nascita</label>
                                        <p>{data.data_nascita ? formatDate(data.data_nascita, 'long') : '-'}</p>
                                    </div>
                                    <div className="profile-page__info-item">
                                        <label>Sesso</label>
                                        <p>{data.sesso === 'M' ? 'Maschio' : data.sesso === 'F' ? 'Femmina' : '-'}</p>
                                    </div>
                                </div>
                            ) : (
                                <form onSubmit={handleSaveProfile}>
                                    <div className="profile-page__form-grid">
                                        <div className="profile-page__form-item">
                                            <Input
                                                required
                                                name="username"
                                                title="Username"
                                                value={data?.username || ''}
                                                onInput={handleInputChange}
                                                error={errors.username}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Input
                                                required
                                                name="email"
                                                title="Email"
                                                type="email"
                                                value={data?.email || ''}
                                                onInput={handleInputChange}
                                                error={errors.email}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Input
                                                name="nome"
                                                title="Nome"
                                                value={data.nome || ''}
                                                onInput={handleInputChange}
                                                error={errors.nome}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Input
                                                name="cognome"
                                                title="Cognome"
                                                value={data.cognome || ''}
                                                onInput={handleInputChange}
                                                error={errors.cognome}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Input
                                                name="cellulare"
                                                title="Cellulare"
                                                type="tel"
                                                value={data.cellulare || ''}
                                                onInput={handleInputChange}
                                                error={errors.cellulare}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Input
                                                name="data_nascita"
                                                title="Data di nascita"
                                                type="date"
                                                value={data.data_nascita ? data.data_nascita.split('T')[0] : ''}
                                                onInput={handleInputChange}
                                                error={errors.data_nascita}
                                            />
                                        </div>
                                        <div className="profile-page__form-item">
                                            <Select
                                                name="sesso"
                                                title="Sesso"
                                                value={data.sesso || ''}
                                                onInput={handleInputChange}
                                                error={errors.sesso}
                                                options={[
                                                    { name: 'Maschio', value: 'M' },
                                                    { name: 'Femmina', value: 'F' },
                                                ]}
                                            />
                                        </div>
                                    </div>
                                    <div className="profile-page__form-actions flex-column flex-md-row">
                                        <Button
                                            type="button"
                                            variant="outline-primary"
                                            onClick={handleCancelEdit}
                                        >
                                            Annulla
                                        </Button>
                                        <Button
                                            type="submit"
                                            variant="primary"
                                            disabled={loading}
                                        >
                                            {loading ? (
                                                <>
                                                    <i className="fa fa-spinner fa-spin me-2"></i>
                                                    <span>Salvataggio in corso</span>
                                                </>
                                            ) : (
                                                <>
                                                    <i className="fas fa-save me-2"></i>
                                                    <span>Salva modifiche</span>
                                                </>
                                            )}
                                        </Button>
                                    </div>
                                </form>
                            )}

                            {!isEditing && (
                                <div className="profile-page__actions">
                                    <Button
                                        variant="primary"
                                        onClick={() => setIsEditing(true)}>
                                        <i className="fas fa-edit me-2"></i>
                                        Modifica profilo
                                    </Button>
                                </div>
                            )}
                        </div>
                    </Card.Body>
                </Card>

                {/* Sezione Sessioni */}
                <Card className="profile-page__card profile-page__card--sessions">
                    <Card.Body>
                        <div className="profile-page__sessions-header">
                            <div>
                                <div className="d-flex align-items-center gap-2 mb-2">
                                    <h2 className="profile-page__sessions-title mb-0">Sessioni attive</h2>
                                    <Button
                                        variant="link"
                                        className="btn-reload"
                                        onClick={() => dispatch(fetchSessions())}
                                        disabled={sessionsLoading}
                                        size="sm"
                                        title="Ricarica sessioni"
                                    >
                                        <i className={"fas fa-sync-alt" + (sessionsLoading ? ' fa-spin' : '')}></i>
                                    </Button>
                                </div>
                                <p className="profile-page__sessions-subtitle">
                                    Gestisci i dispositivi e le sessioni dove hai effettuato l'accesso
                                </p>
                            </div>
                            {sessions.filter(s => !s.isCurrent).length > 0 && (
                                <Button
                                    variant="outline-danger"
                                    size="sm"
                                    onClick={handleInvalidateAllOthers}
                                >
                                    <i className="fas fa-sign-out-alt me-2"></i>
                                    Disconnetti tutte le altre sessioni
                                </Button>
                            )}
                        </div>

                        <div className="profile-page__sessions-list">
                            {sessionsLoading ? (
                                <div className="profile-page__sessions-loading">
                                    <div className="spinner-border" role="status">
                                        <span className="visually-hidden">Caricamento...</span>
                                    </div>
                                    <p className="mt-3">Caricamento sessioni...</p>
                                </div>
                            ) : sessions.length === 0 ? (
                                <div className="profile-page__sessions-empty">
                                    <i className="fas fa-info-circle"></i>
                                    <p>Nessuna sessione trovata</p>
                                </div>
                            ) : (
                                sessions.map((session) => (
                                    <div
                                        key={session.id}
                                        className={`profile-page__session-item ${session.isCurrent ? 'profile-page__session-item--current' : ''}`}
                                    >
                                        <div className="profile-page__session-icon">
                                            <i className={`fas ${
                                                session.deviceType === 'Desktop' ? 'fa-desktop' :
                                                session.deviceType === 'Mobile' ? 'fa-mobile-alt' :
                                                session.deviceType === 'Tablet' ? 'fa-tablet-alt' :
                                                'fa-laptop'
                                            }`}></i>
                                        </div>
                                        <div className="profile-page__session-info">
                                            <div className="profile-page__session-header">
                                                <h5 className="profile-page__session-device">
                                                    {session.device}
                                                    {session.isCurrent && (
                                                        <Badge bg="success" className="ms-2">Attuale</Badge>
                                                    )}
                                                </h5>
                                            </div>
                                            <div className="profile-page__session-details">
                                                <span className="profile-page__session-detail">
                                                    <i className="fas fa-network-wired"></i>
                                                    {session.ip}
                                                </span>
                                                <span className="profile-page__session-detail">
                                                    <i className="fas fa-clock"></i>
                                                    {session.hasLastUsedAt
                                                        ? `Ultima attività: ${formatDateTime(session.lastActivity)}`
                                                        : `Creata il: ${formatDateTime(session.lastActivity)}`
                                                    }
                                                </span>
                                            </div>
                                        </div>
                                        {!session.isCurrent && (
                                            <div className="profile-page__session-actions">
                                                <Button
                                                    variant="outline-danger"
                                                    size="sm"
                                                    onClick={() => openInvalidateModal(session)}
                                                >
                                                    <i className="fas fa-ban me-1"></i>
                                                    Disconnetti
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>
                    </Card.Body>
                </Card>
            </div>

            {/* Modale conferma invalidazione sessione */}
            <Modal
                show={showInvalidateModal}
                onHide={() => {
                    setShowInvalidateModal(false);
                    setSessionToInvalidate(null);
                }}
                centered
            >
                <Modal.Header closeButton>
                    <Modal.Title>Conferma disconnessione</Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    <p>Sei sicuro di voler disconnettere questa sessione?</p>
                    {sessionToInvalidate && (
                        <div className="mt-3 p-3 bg-light rounded">
                            <strong>{sessionToInvalidate.device}</strong>
                            <br />
                            <small className="text-muted">
                                {sessionToInvalidate.ip}
                            </small>
                        </div>
                    )}
                </Modal.Body>
                <Modal.Footer>
                    <Button
                        variant="outline-secondary"
                        onClick={() => {
                            setShowInvalidateModal(false);
                            setSessionToInvalidate(null);
                        }}
                    >
                        Annulla
                    </Button>
                    <Button
                        variant="danger"
                        onClick={() => handleInvalidateSession(sessionToInvalidate?.id)}
                    >
                        Disconnetti
                    </Button>
                </Modal.Footer>
            </Modal>
        </BaseLayout>
    );
};

export default Profilo;

