import React, { useState } from 'react';
import ChartControls from './ChartControls';
import ExerciseStats from './ExerciseStats';
import ChartContainer from './ChartRenderer';

const ExerciseChart = ({ exercise }) => {
    const [chartType, setChartType] = useState('combined');
    const data = exercise.chartData;

    return (
        <div className="exercise-chart-card">
            <div className="exercise-chart-header">
                <div>
                    <h4 className="exercise-name">{exercise.nome}</h4>
                    <span className="badge badge-muscle">{exercise.gruppoMuscolare}</span>
                    <span className="badge badge-day">Giorno {exercise.day}</span>
                </div>
                <ChartControls 
                    chartType={chartType} 
                    onChartTypeChange={setChartType} 
                />
            </div>

            <ExerciseStats data={data} />

            <ChartContainer chartType={chartType} data={data} />
        </div>
    );
};

export default ExerciseChart;
