import axios from "axios";
import { TokenService } from "../services/token.service";

const instance = axios.create({
    headers: {
        Accept: "application/json"
    }
    // .. other options
});

// Funzione per ottenere il token aggiornato dal localStorage
const getToken = () => localStorage.getItem('ACCESS_TOKEN');

/* Metto la rotta di login in una costante poiché da webserver il base path è /app */
const LOGIN_ROUTE = "/app/login";
/**
 * Funzione globale per gestire il reindirizzamento in caso di errore 401
 */
const redirectToLogin = () => {
    TokenService.resetToken(); // Pulisce il localStorage
    window.location.href = LOGIN_ROUTE; // Redirect alla pagina di login
};

// Intercetto la richiesta, se presente un token nel localStorage lo aggiungo, altrimenti lascio inalterata la richiesta
instance.interceptors.request.use(
    config => {
        const token = getToken();
        if (token) {
            config.headers['Authorization'] = token;
        }
        return config;
    },
    err => {
        return Promise.reject(err);
    });

// Prendo l'ultimo token nella risposta (se esiste) e lo aggiorno nel localStorage
instance.interceptors.response.use(
    res => {
        if (!!res.headers.authorization) {
            TokenService.setToken({ token: res.headers.authorization });
        }
        return res;
    },
    err => {
        // ⚠️ Se err.response è undefined, significa che il server non ha risposto (es. errore di rete)
        if (!err.response) {
            return Promise.reject({ message: "Errore di rete, server non raggiungibile", originalError: err });
        }

        // Vado a settare il token aggiornato anche in caso di errore, altrimenti la prossima chiamata restituirà un 401
        if (!!err.response.headers?.authorization) {
            TokenService.setToken({ token: err.response.headers.authorization });
        }

        // Se l'utente non è autenticato (errore 401) e non mi trovo sulla pagina di login...
        if (err.response.status === 401 && ![LOGIN_ROUTE].includes(window.location.pathname)) {
            // Rendirizzo l'utente alla pagina di login
            redirectToLogin();
        }

        return Promise.reject(err);
    }
);

export default instance;