import { useEffect, useRef, useState } from 'react';
import { Form } from 'react-bootstrap';

const FiltersDropdown = ({
    children,
    activeCount = 0,
    onSubmit,
    onReset,
}) => {
    const [open, setOpen] = useState(false);
    const ref = useRef(null);

    useEffect(() => {
        const handleClickOutside = (e) => {
            if (ref.current && !ref.current.contains(e.target)) setOpen(false);
        };
        document.addEventListener('mousedown', handleClickOutside, true);
        return () => document.removeEventListener('mousedown', handleClickOutside, true);
    }, []);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSubmit?.();
    };

    const handleReset = () => {
        onReset?.();
    };

    return (
        <div className="filters-dropdown mb-4" ref={ref}>
            <div className="filters-trigger-row">
                <button
                    type="button"
                    className={`filters-toggle${open ? ' open' : ''}`}
                    onClick={() => setOpen((prev) => !prev)}
                >
                    <i className="fas fa-sliders-h" />
                    <span>Filtri</span>
                    {activeCount > 0 && (
                        <span className="filters-badge">{activeCount}</span>
                    )}
                    <i className={`fas fa-chevron-down filters-chevron${open ? ' open' : ''}`} />
                </button>

                {activeCount > 0 && (
                    <button
                        type="button"
                        className="filters-clear-button"
                        onClick={handleReset}
                        title="Rimuovi tutti i filtri"
                    >
                        <i className="fas fa-xmark" /> Reset filtri
                    </button>
                )}
            </div>

            {open && (
                <div className="filters-panel">
                    <Form onSubmit={handleSubmit}>
                        <div className="filters-list">
                            {children}
                        </div>

                        <div className="filters-actions">
                            <button
                                type="button"
                                className="filters-reset-button"
                                onClick={handleReset}
                            >
                                <i className="fas fa-rotate-left" />
                                <span>Reset</span>
                            </button>
                            <button type="submit" className="filters-submit-button">
                                <i className="fas fa-filter" />
                                <span>Filtra</span>
                            </button>
                        </div>
                    </Form>
                </div>
            )}
        </div>
    );
};

export default FiltersDropdown;
