/**
 * Processa i dati delle sessioni per un esercizio specifico
 * @param {number} exerciseId - ID dell'esercizio
 * @param {string} day - Giorno di allenamento
 * @param {object} sessions - Oggetto contenente le sessioni per giorno
 * @returns {array|null} Array di dati processati per il grafico o null se non ci sono dati
 */
export const processExerciseData = (exerciseId, day, sessions) => {
    const exerciseSessions = sessions[day]?.filter(
        session => session.protocol_exercise_id === exerciseId && session.is_completed === 1
    ) || [];

    if (exerciseSessions.length === 0) return null;

    const chartData = exerciseSessions
        .map((session, index) => {
            const weights = session.weights || [];
            const reps = session.reps || [];
            
            // Calcola medie e totali
            const avgWeight = weights.length > 0 
                ? weights.reduce((sum, w) => sum + w, 0) / weights.length 
                : 0;
            const avgReps = reps.length > 0 
                ? reps.reduce((sum, r) => sum + r, 0) / reps.length 
                : 0;
            const totalVolume = weights.reduce((sum, w, i) => sum + (w * (reps[i] || 0)), 0);
            const maxWeight = weights.length > 0 ? Math.max(...weights) : 0;
            const maxReps = reps.length > 0 ? Math.max(...reps) : 0;

            // Formatta la data
            const date = new Date(session.session_date);
            const formattedDate = date.toLocaleDateString('it-IT', { 
                day: '2-digit', 
                month: 'short' 
            });

            return {
                sessionNumber: index + 1,
                date: formattedDate,
                fullDate: session.session_date,
                avgWeight: Math.round(avgWeight * 10) / 10,
                avgReps: Math.round(avgReps * 10) / 10,
                totalVolume: Math.round(totalVolume),
                maxWeight,
                maxReps,
                weights: weights,
                reps: reps,
                sets: weights.length
            };
        })
        .sort((a, b) => new Date(a.fullDate) - new Date(b.fullDate));

    return chartData;
};

/**
 * Ottiene tutti gli esercizi con dati disponibili
 * @param {object} workout - Oggetto workout contenente esercizi_x_day
 * @param {object} sessions - Oggetto contenente le sessioni
 * @returns {array} Array di esercizi con dati processati
 */
export const getExercisesWithData = (workout, sessions) => {
    if (!workout.esercizi_x_day || !sessions) return [];

    const exercises = [];
    Object.entries(workout.esercizi_x_day).forEach(([day, dayExercises]) => {
        dayExercises.forEach(exercise => {
            const data = processExerciseData(exercise.id, day, sessions);
            if (data && data.length > 0) {
                exercises.push({
                    ...exercise,
                    day,
                    chartData: data,
                    sessionCount: data.length
                });
            }
        });
    });

    return exercises;
};

/**
 * Ottiene gli esercizi con dati disponibili mantenendo la struttura originale per giorno
 * @param {object} workout - Oggetto workout contenente esercizi_x_day
 * @param {object} sessions - Oggetto contenente le sessioni
 * @returns {object} Oggetto con chiavi = giorno, valori = array di esercizi con dati processati
 */
export const getExercisesWithDataByDay = (workout, sessions) => {
    if (!workout.esercizi_x_day || !sessions) return {};

    const exercisesByDay = {};
    
    Object.entries(workout.esercizi_x_day).forEach(([day, dayExercises]) => {
        exercisesByDay[day] = dayExercises
            .map(exercise => {
                const data = processExerciseData(exercise.id, day, sessions);
                if (data && data.length > 0) {
                    return {
                        ...exercise,
                        day,
                        chartData: data,
                        sessionCount: data.length
                    };
                }
                return null;
            })
            .filter(exercise => exercise !== null); // Rimuove gli esercizi senza dati
    });

    return exercisesByDay;
};

/**
 * Raggruppa esercizi per giorno
 * @param {array} exercises - Array di esercizi
 * @returns {object} Oggetto con chiavi = giorno, valori = array di esercizi
 */
export const groupExercisesByDay = (exercises) => {
    const grouped = {};
    exercises.forEach(exercise => {
        if (!grouped[exercise.day]) {
            grouped[exercise.day] = [];
        }
        grouped[exercise.day].push(exercise);
    });
    return grouped;
};

/**
 * Raggruppa esercizi per gruppo muscolare
 * @param {array} exercises - Array di esercizi
 * @returns {object} Oggetto con chiavi = gruppo muscolare, valori = array di esercizi
 */
export const groupExercisesByMuscleGroup = (exercises) => {
    const grouped = {};
    exercises.forEach(exercise => {
        const key = exercise.gruppoMuscolare;
        if (!grouped[key]) {
            grouped[key] = [];
        }
        grouped[key].push(exercise);
    });
    return grouped;
};
