import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { logoutUser } from '../features/user/userSlice';
import { getUserInitials, getUserName } from '../functions';
import { useAuth } from '../hooks/useAuth';

const Sidebar = ({ isOpen, onClose }) => {
    const dispatch = useDispatch();
    const location = useLocation();
    const { user, isAdmin } = useAuth();

    const handleLogout = () => {
        dispatch(logoutUser());
    };

    const isActive = (path) => {
        if (path === '/workouts/last') {
            // "Scheda" è attivo solo per /workouts/last o /workouts/last/*
            return location.pathname === '/workouts/last' || location.pathname.startsWith('/workouts/last/');
        }
        if (path === '/workouts') {
            // "I miei Workout" è attivo per /workouts ma NON per /workouts/last
            return location.pathname.startsWith('/workouts') && !location.pathname.startsWith('/workouts/last');
        }
        if (path === '/progress') {
            return location.pathname.startsWith('/progress');
        }
        if (path === '/exercises') {
            return location.pathname.startsWith('/exercises');
        }
        return location.pathname === path;
    };

    const menuItems = [
        {
            path: '/workouts/last',
            icon: 'fa-dumbbell',
            label: 'Scheda',
            exact: false
        },
        {
            path: '/workouts',
            icon: 'fa-list',
            label: 'I miei Workouts'
        },
        {
            path: '/scheda/create',
            icon: 'fa-plus-circle',
            label: 'Aggiungi Workout'
        },
        {
            path: '/progress',
            icon: 'fa-chart-line',
            label: 'Progressi'
        }
    ];

    const secondaryItems = [
        {
            path: '/profile',
            icon: 'fa-user',
            label: 'Il mio Profilo'
        }
    ];

    const adminItems = [
        {
            path: '/exercises',
            icon: 'fa-dumbbell',
            label: 'Gestione Esercizi'
        }
    ];

    return (
        <>
            {/* Overlay per mobile quando sidebar è aperta */}
            {isOpen && (
                <div 
                    className="sidebar-overlay"
                    onClick={onClose}
                    aria-hidden="true"
                />
            )}

            {/* Sidebar */}
            <aside className={`app-sidebar ${isOpen ? 'app-sidebar--open' : ''}`}>
                <div className="app-sidebar__header">
                    <div className="app-sidebar__logo">
                        <img 
                            src={`${process.env.PUBLIC_URL}/logo_train-up_white_350px.png`}
                            alt="Train UP Logo" 
                            className="app-sidebar__logo-img"
                        />
                    </div>
                    <button 
                        className="app-sidebar__close"
                        onClick={onClose}
                        aria-label="Chiudi sidebar"
                    >
                        <i className="fas fa-times"></i>
                    </button>
                </div>

                <nav className="app-sidebar__nav">
                    <div className="app-sidebar__section">
                        {menuItems.map((item) => {
                            if (item.disabled) {
                                return (
                                    <div 
                                        key={item.path}
                                        className="app-sidebar__item app-sidebar__item--disabled"
                                    >
                                        <i className={`fa-solid ${item.icon}`}></i>
                                        <span>{item.label}</span>
                                    </div>
                                );
                            }

                            return (
                                <Link
                                    key={item.path}
                                    to={item.path}
                                    className={`app-sidebar__item ${isActive(item.path) ? 'app-sidebar__item--active' : ''}`}
                                    onClick={onClose}
                                >
                                    <i className={`fa-solid ${item.icon}`}></i>
                                    <span>{item.label}</span>
                                </Link>
                            );
                        })}
                    </div>

                    <div className="app-sidebar__divider"></div>

                    <div className="app-sidebar__section">
                        {secondaryItems.map((item) => (
                            <Link
                                key={item.path}
                                to={item.path}
                                className={`app-sidebar__item ${isActive(item.path) ? 'app-sidebar__item--active' : ''}`}
                                onClick={onClose}
                            >
                                <i className={`fa-solid ${item.icon}`}></i>
                                <span>{item.label}</span>
                            </Link>
                        ))}
                    </div>

                    {/* Sezione Admin - visibile solo per admin (tipoUtente = 3) */}
                    {isAdmin && (
                        <>
                            <div className="app-sidebar__divider"></div>
                            <div className="app-sidebar__section">
                                <div className="app-sidebar__section-title">Admin</div>
                                {adminItems.map((item) => (
                                    <Link
                                        key={item.path}
                                        to={item.path}
                                        className={`app-sidebar__item ${isActive(item.path) ? 'app-sidebar__item--active' : ''}`}
                                        onClick={onClose}
                                    >
                                        <i className={`fa-solid ${item.icon}`}></i>
                                        <span>{item.label}</span>
                                    </Link>
                                ))}
                            </div>
                        </>
                    )}

                    <div className="app-sidebar__divider"></div>

                    <div className="app-sidebar__section">
                        <button
                            className="app-sidebar__item app-sidebar__item--logout"
                            onClick={handleLogout}
                        >
                            <i className="fa-solid fa-sign-out-alt"></i>
                            <span>Logout</span>
                        </button>
                    </div>
                </nav>

                {user && (
                    <div className="app-sidebar__footer">
                        <div className="app-sidebar__user">
                            <div className="app-sidebar__user-avatar">
                                {user.avatar_url ? (
                                    <img
                                        src={user.avatar_url}
                                        alt="Avatar"
                                        className="app-sidebar__user-avatar-img"
                                    />
                                ) : (
                                    <div className="app-sidebar__user-avatar-placeholder">
                                        {getUserInitials(user)}
                                    </div>
                                )}
                            </div>
                            <div className="app-sidebar__user-info">
                                <div className="app-sidebar__user-name">
                                    {getUserName(user)}
                                </div>
                                <div className="app-sidebar__user-email">{user.email}</div>
                            </div>
                        </div>
                    </div>
                )}
            </aside>
        </>
    );
};

export default Sidebar;

