export const TokenService = {
    setToken: function ({ token, expiresIn = null }) {
        localStorage.setItem('ACCESS_TOKEN', token);
    },

    getToken: function () {
        return localStorage.getItem('ACCESS_TOKEN');
    },
    
    resetToken: function () {
        localStorage.clear();
    },

    isExistToken: function () {
        return !!localStorage.getItem('ACCESS_TOKEN');
    },
};