import React from 'react';
import {
    LineChart,
    Line,
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    ComposedChart
} from 'recharts';
import CustomTooltip from './CustomTooltip';

// Colori della palette Train UP per i grafici
const CHART_COLORS = {
    primary: '#AFDE1F',      // Verde Primario
    secondary: '#FF8C42',    // Arancione per serie secondarie (complementare al verde)
    grid: '#8F8F8F'          // Grigio Chiaro per griglia
};

const ChartRenderer = ({ chartType, data }) => {
    const commonProps = {
        data,
        margin: { top: 5, right: 30, left: 20, bottom: 5 }
    };

    switch (chartType) {
        case 'combined':
            return (
                <ComposedChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_COLORS.grid} />
                    <XAxis 
                        dataKey="sessionNumber" 
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        yAxisId="left"
                        label={{ value: 'Peso (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <YAxis 
                        yAxisId="right" 
                        orientation="right"
                        label={{ value: 'Ripetizioni', angle: 90, position: 'insideRight' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Bar 
                        yAxisId="left"
                        dataKey="avgWeight" 
                        fill={CHART_COLORS.primary} 
                        name="Peso Medio (kg)"
                        radius={[4, 4, 0, 0]}
                    />
                    <Line 
                        yAxisId="right"
                        type="monotone" 
                        dataKey="avgReps" 
                        stroke={CHART_COLORS.secondary} 
                        strokeWidth={2}
                        name="Ripetizioni Medie"
                        dot={{ r: 5, fill: CHART_COLORS.secondary }}
                    />
                </ComposedChart>
            );

        case 'weight':
            return (
                <LineChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_COLORS.grid} />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Peso (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Line 
                        type="monotone" 
                        dataKey="avgWeight" 
                        stroke={CHART_COLORS.primary} 
                        strokeWidth={3}
                        name="Peso Medio (kg)"
                        dot={{ r: 6, fill: CHART_COLORS.primary }}
                        activeDot={{ r: 8, fill: CHART_COLORS.primary }}
                    />
                    <Line 
                        type="monotone" 
                        dataKey="maxWeight" 
                        stroke={CHART_COLORS.secondary} 
                        strokeWidth={2}
                        strokeDasharray="5 5"
                        name="Peso Massimo (kg)"
                        dot={{ r: 4, fill: CHART_COLORS.secondary }}
                    />
                </LineChart>
            );

        case 'reps':
            return (
                <LineChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_COLORS.grid} />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Ripetizioni', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Line 
                        type="monotone" 
                        dataKey="avgReps" 
                        stroke={CHART_COLORS.primary} 
                        strokeWidth={3}
                        name="Ripetizioni Medie"
                        dot={{ r: 6, fill: CHART_COLORS.primary }}
                        activeDot={{ r: 8, fill: CHART_COLORS.primary }}
                    />
                    <Line 
                        type="monotone" 
                        dataKey="maxReps" 
                        stroke={CHART_COLORS.secondary} 
                        strokeWidth={2}
                        strokeDasharray="5 5"
                        name="Ripetizioni Massime"
                        dot={{ r: 4, fill: CHART_COLORS.secondary }}
                    />
                </LineChart>
            );

        case 'volume':
            return (
                <BarChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_COLORS.grid} />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Volume (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Bar 
                        dataKey="totalVolume" 
                        fill={CHART_COLORS.primary} 
                        name="Volume Totale (kg)"
                        radius={[8, 8, 0, 0]}
                    />
                </BarChart>
            );

        default:
            return null;
    }
};

const ChartContainer = ({ chartType, data }) => {
    return (
        <div className="chart-container">
            <ResponsiveContainer width="100%" height={300}>
                <ChartRenderer chartType={chartType} data={data} />
            </ResponsiveContainer>
        </div>
    );
};

export default ChartContainer;
