import React from 'react';
import { Link } from 'react-router-dom';

const SchedaHeader = ({ workout, progressPath, handleReloadData, loading }) => {
    const formatDate = (dateString) => {
        if (!dateString) return null;
        const date = new Date(dateString);
        return date.toLocaleDateString('it-IT', { 
            day: 'numeric', 
            month: 'long', 
            year: 'numeric' 
        });
    };

    const totalExercises = Object.values(workout.esercizi_x_day || {}).flat().length;
    const totalDays = workout.numeroAllSettimanali;

    return (
        <div className="scheda-header">
            <div className="scheda-header__content">
                <div className="scheda-header__main">
                    <div className="scheda-header__title-section">
                        <h1 className="scheda-header__title">{workout.nomeScheda}</h1>
                        <div className="scheda-header__meta">
                            <span className="meta-item">
                                <i className="fas fa-calendar-days"></i>
                                {totalDays} {totalDays === 1 ? 'giorno' : 'giorni'}
                            </span>
                            <span className="meta-item">
                                <i className="fas fa-dumbbell"></i>
                                {totalExercises} {totalExercises === 1 ? 'esercizio' : 'esercizi'}
                            </span>
                            {workout.dataDiScadenza && (
                                <span className="meta-item">
                                    <i className="fas fa-clock"></i>
                                    Scade il {formatDate(workout.dataDiScadenza)}
                                </span>
                            )}
                        </div>
                    </div>
                </div>

                <div className="scheda-header__actions">
                    <Link
                        to={progressPath}
                        className="scheda-header__btn scheda-header__btn--primary"
                        title="Visualizza Progressi"
                    >
                        <i className="fas fa-chart-line"></i>
                        <span>Progressi</span>
                    </Link>
                    <button
                        onClick={handleReloadData}
                        className="scheda-header__btn scheda-header__btn--secondary"
                        disabled={loading}
                        title="Ricarica dati"
                    >
                        <i className={`fas fa-sync-alt ${loading ? "fa-spin" : ""}`}></i>
                        <span>Aggiorna</span>
                    </button>
                </div>
            </div>
        </div>
    );
};

export default SchedaHeader;


