export const Form = ({ className = null, children }) => {
    const onSubmit = (e) => {
        e.preventDefault();
    }

    return (
        <form onSubmit={onSubmit} className={className} noValidate>
            {children}
        </form>
    );
}

export const Label = ({ title, htmlFor, required = false }) => {
    if (title) {
        return (
            <label className="form-group-label" htmlFor={htmlFor}>
                {title}
                {required && <span className="required-mark"> *</span>}
            </label>
        )
    }
}

export const Input = ({ name, title, required = false, type = 'text', placeholder = "Inserisci valore", value = null, onInput, onFocus = null, autoComplete = 'off', min = null, max = null, error = null }) => {
    return (
        <div className="form-group-wp">
            <Label title={title} htmlFor={name} required={required} />
            <input
                type={type}
                name={name}
                placeholder={placeholder}
                value={value != null ? value : ''}
                min={min}
                max={max}
                onChange={onInput}
                onFocus={onFocus}
                autoComplete={autoComplete}
                className={`form-control my-form-control${error ? " is-invalid" : ''}`} />
            {error && <InputError error={error} />}
        </div>
    );
}

export const Textarea = ({ name, title, required = false, type = 'text', placeholder = null, value = null, onInput, autoComplete = 'off', errors = null }) => {
    return (
        <>
            <Label title={title} htmlFor={name} required={required} />
            <textarea rows={'3'} type={type} name={name} placeholder={placeholder} value={value != null ? value : ''} onChange={onInput} autoComplete={autoComplete} />
            {errors && <InputError error={errors[name]} />}
        </>
    );
}

export const Select = ({ name, title, required = false, options = [], value, onInput, error = null }) => {
    return (
        <div className="form-group-wp">
            <Label title={title} htmlFor={name} required={required} />
            <select
                name={name}
                value={!!value ? value : 'default'}
                onChange={onInput}
                className={`form-control my-form-control${error ? " is-invalid" : ''}`}
            >
                <option value='default' disabled>Seleziona un'opzione</option>
                {options.map((e, i) => (
                    <option value={e.value} key={i}>{e.name}</option>
                ))}
            </select>
            {error && <InputError error={error} />}
        </div>
    );
}

export const SearchInput = ({ name, placeholder = 'Cerca...', value, onInput }) => {
    return (
        <div className="search-input-wrapper">
            <i className="fas fa-search search-input-icon" />
            <input
                type="text"
                name={name}
                placeholder={placeholder}
                value={value ?? ''}
                onChange={onInput}
                autoComplete="off"
                className="form-control"
            />
        </div>
    );
};

export const InputError = ({ error = null }) => {
    if (!error) return <></>

    return (
        <span role="alert" className="invalid-feedback"><strong>{error}</strong></span>
    )
}
