import { useMemo, useState } from 'react';
import { SearchInput, Select } from './FormComponents';
import FiltersDropdown from './FiltersDropdown';

const MUSCLE_GROUP_ALL = 'all';

const ExercisesFilters = ({
    muscleGroups = [],
    search,
    customFilters,
    applyFilters = () => { },
}) => {
    const [searchInput, setSearchInput] = useState(search ?? '');
    const [muscleGroupInput, setMuscleGroupInput] = useState(customFilters.muscle_group_id ?? MUSCLE_GROUP_ALL);

    const activeCount = useMemo(() => {
        let count = Object.keys(customFilters).length;
        if (search) count++;
        return count;
    }, [customFilters, search]);

    const muscleGroupOptions = useMemo(() => [
        { value: MUSCLE_GROUP_ALL, name: 'Tutti' },
        ...muscleGroups.map(g => ({ value: g.value, name: g.label })),
    ], [muscleGroups]);

    const handleSubmit = () => {
        const filtersToSet = muscleGroupInput && muscleGroupInput !== MUSCLE_GROUP_ALL
            ? { muscle_group_id: muscleGroupInput }
            : {};
        const filtersToRemove = muscleGroupInput === MUSCLE_GROUP_ALL ? ['muscle_group_id'] : [];
        applyFilters({ search: searchInput, set: filtersToSet, remove: filtersToRemove });
    };

    const handleReset = () => {
        setSearchInput('');
        setMuscleGroupInput(MUSCLE_GROUP_ALL);
        applyFilters({ search: '', set: {}, remove: ['muscle_group_id'] });
    };

    return (
        <FiltersDropdown activeCount={activeCount} onSubmit={handleSubmit} onReset={handleReset}>
            <div className="filter-item">
                <SearchInput
                    name="search"
                    placeholder="Cerca per nome..."
                    value={searchInput}
                    onInput={(e) => setSearchInput(e.target.value)}
                />
            </div>
            <div className="filter-item">
                <Select
                    name="muscleGroupId"
                    title="Gruppo Muscolare"
                    options={muscleGroupOptions}
                    value={muscleGroupInput}
                    onInput={(e) => setMuscleGroupInput(e.target.value)}
                />
            </div>
        </FiltersDropdown>
    );
};

export default ExercisesFilters;
