import React, { useEffect, useMemo, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import BaseLayout from '../components/BaseLayout';
import PageHeader from '../components/PageHeader';
import { clearErrors, fetchWorkout, lastScheda } from '../features/workout/workoutSlice';
import { SchedaService } from '../services/scheda.service';
import ProgressFilters from '../components/Progress/ProgressFilters';
import DaySection from '../components/Progress/DaySection';
import EmptyState from '../components/Progress/EmptyState';
import ProgressStats from '../components/Progress/ProgressStats';
import { getExercisesWithDataByDay } from '../utils/progressUtils';

const ProgressPageHeader = ({ workout, handleReloadData, loading }) => {
    return (
        <PageHeader
            title="Progressi Allenamento"
            subtitle={workout.nomeScheda}
            actions={[
                <button
                    key="reload"
                    onClick={handleReloadData}
                    className="btn btn-reload fs-4 p-2"
                    disabled={loading}
                >
                    <i className={`fas fa-sync-alt ${loading ? "fa-spin" : ""}`}></i>
                </button>
            ]}
        />
    )
}

const Progress = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const { id = null } = useParams();
    const [searchParams, setSearchParams] = useSearchParams();
    const { workout, sessions, latestWorkoutId, errors } = useSelector(state => state.workout);
    const { loading } = useSelector(state => state.loader);

    // Recupera il giorno dai query params, se presente
    const dayFromParams = searchParams.get('day');
    const [selectedDay, setSelectedDay] = useState(dayFromParams || null);

    // Ottieni tutti gli esercizi con dati disponibili
    const { exercisesWithDataByDay, availableDays } = useMemo(() => {
        const exercisesWithDataByDay = getExercisesWithDataByDay(workout, sessions);
        const availableDays = Object.keys(exercisesWithDataByDay);

        return { exercisesWithDataByDay, availableDays };
    }, [workout, sessions]);

    const filteredExercises = useMemo(() => {
        return selectedDay
            ? { [selectedDay]: exercisesWithDataByDay[selectedDay] || [] }
            : exercisesWithDataByDay;
    }, [selectedDay, exercisesWithDataByDay]);

    // Funzione per gestire il cambio del filtro giorno
    const handleDayChange = (day) => {
        setSelectedDay(day);
        // Aggiorna i query params
        if (day) {
            setSearchParams({ day: day.toString() });
        } else {
            setSearchParams({});
        }
    };

    // Sincronizza lo stato con i query params quando cambiano
    useEffect(() => {
        const dayFromParams = searchParams.get('day');
        if (dayFromParams !== selectedDay?.toString()) {
            setSelectedDay(dayFromParams || null);
        }
    }, [searchParams]);

    const handleReloadData = () => {
        if (!!id) {
            dispatch(fetchWorkout(id));
        } else {
            SchedaService.clearWorkout();
            dispatch(lastScheda());
        }
    };

    useEffect(() => {
        if (!!id) {
            if (!!workout.idScheda && workout.idScheda == id) return;
            dispatch(fetchWorkout(id));
        } else {
            if (!!workout.idScheda && workout.idScheda === latestWorkoutId) return;
            dispatch(lastScheda());
        }
    }, [dispatch, id, workout.idScheda, latestWorkoutId]);

    useEffect(() => {
        if (!!Object.keys(errors).length) {
            const { status_code: code, message, info, cta, redirect_link } = errors;
            dispatch(clearErrors());
            if (redirect_link) {
                navigate(redirect_link);
            } else {
                navigate("/error", {
                    state: {
                        code,
                        message,
                        cta: {
                            description: info || null,
                            actionLabel: cta?.label || "Ritorna alla home",
                            route: cta?.action || "/workouts/last"
                        }
                    }
                });
            }
        }
    }, [errors, dispatch, navigate]);

    if (!workout.idScheda) {
        return (
            <BaseLayout>
                <div className="page-content">
                    <div className="text-center py-5">
                        <p>Caricamento dati...</p>
                    </div>
                </div>
            </BaseLayout>
        );
    }

    return (
        <BaseLayout>
            <div className="page-content progress-page">
                <ProgressPageHeader {...{ workout, handleReloadData, loading }} />
                
                {!Object.values(filteredExercises).flat().length ? (
                    <EmptyState />
                ) : (
                    <>
                        <ProgressStats exercisesWithDataByDay={exercisesWithDataByDay} />
                        
                        <ProgressFilters
                            selectedDay={selectedDay}
                            onDayChange={handleDayChange}
                            availableDays={availableDays}
                        />

                        <div className="progress-content">
                            {Object.entries(filteredExercises).map(([day, exercises]) => (
                                <DaySection
                                    key={day}
                                    day={day}
                                    exercises={exercises}
                                />
                            ))}
                        </div>
                    </>
                )}
            </div>
        </BaseLayout>
    );
};

export default Progress;
