import React, { useState } from 'react'
import { Button } from 'react-bootstrap'
import { Input, InputError, Label } from './FormComponents';
import Select from 'react-select';
import { EsercizioService } from '../services/esercizio.service';

const FormEsercizioScheda = ({ dayIndex = 0,
    exercise = {},
    exerciseIndex = 0,
    setDays,
    onInputHandler = () => { },
    removeEsercizio = () => { },
    errors = {} }) => {
    const [options, setOptions] = useState([]);
    // Timer per gestire il debounce
    let debounceTimeout;

    // Gestore per aggiornare la selezione di un `Select` specifico
    const handleSelectChange = (dayIndex, exerciseIndex, selectedOption) => {
        const { label = null, value = null } = selectedOption || {};

        setDays((prevDays) => {
            const newDays = [...prevDays];
            // Copia dell'array exercises
            const newExercises = [...newDays[dayIndex].exercises];
            newExercises[exerciseIndex] = {
                ...newExercises[exerciseIndex],
                nomeEsercizio: label,
                fkEsercizio: value
            }

            newDays[dayIndex] = {
                ...newDays[dayIndex],
                exercises: newExercises
            }

            return newDays;
        });
    };

    // Funzione per caricare le opzioni per ogni `Select`
    const loadOptions = async (query) => {
        try {
            const response = await EsercizioService.search(query);

            setOptions(response.data.result);
        } catch (error) {
        }
    };

    // Funzione chiamata ogni volta che cambia il testo nella casella di ricerca
    const handleInputChange = (inputValue) => {
        // Cancella il timeout precedente
        clearTimeout(debounceTimeout);

        // Imposta un nuovo timeout per il debounce
        debounceTimeout = setTimeout(() => {
            if (!!inputValue) {
                loadOptions(inputValue);  // Chiama l'API solo se l'input non è vuoto
            }
        }, 500);
    };

    return (
        <div id={`esercizio-${exerciseIndex}`} className="form-esercizio col-12">
            <div className="card-form-create-esercizio mb-2">
                {exerciseIndex > 0 ? <Button variant="remove-esercizio" onClick={() => removeEsercizio(dayIndex, exerciseIndex)} /> : ''}
                <div className="row">
                    <div className="col-12 col-lg-6 mb-2">
                        <div className="form-group-wp">
                            <Label htmlFor="nomeEsercizio" title="Nome esercizio" required />
                            <Select
                                required
                                options={options}
                                onInputChange={handleInputChange}
                                onChange={(selectedOption) => handleSelectChange(dayIndex, exerciseIndex, selectedOption)}
                                placeholder="Ricerca il tuo esercizio"
                                isClearable
                                classNamePrefix="esercizio_search_select"
                                className={errors[`days.${dayIndex}.exercises.${exerciseIndex}.fkEsercizio`] ? 'is-invalid' : ''}
                            />
                            <InputError error={errors[`days.${dayIndex}.exercises.${exerciseIndex}.fkEsercizio`] ?? null} />
                        </div>
                    </div>
                    <div className="col-7 col-md-4 col-lg-2 mb-2">
                        <Input required name="numeroRipetizioni"
                            title="Numero ripetizioni"
                            placeholder="Inserisci numero ripetizioni"
                            value={exercise.numeroRipetizioni}
                            error={errors[`days.${dayIndex}.exercises.${exerciseIndex}.numeroRipetizioni`] ?? null}
                            onInput={(e) => onInputHandler(dayIndex, exerciseIndex, e.target.name, e.target.value)} />
                    </div>
                    <div className="col-5 col-md-4 col-lg-2 mb-2">
                        <Input name="serieTotali"
                            title="Serie totali"
                            placeholder="Inserisci serie totali"
                            value={exercise.serieTotali}
                            error={errors[`days.${dayIndex}.exercises.${exerciseIndex}.serieTotali`] ?? null}
                            onInput={(e) => onInputHandler(dayIndex, exerciseIndex, e.target.name, e.target.value)} />
                    </div>
                    <div className="col-12 col-md-4 col-lg-2 mb-2">
                        <Input type="number"
                            name="recuperoXserie"
                            title="Recupero tra serie"
                            placeholder="Recupero in secondi"
                            value={exercise.recuperoXserie}
                            error={errors[`days.${dayIndex}.exercises.${exerciseIndex}.recuperoXserie`] ?? null}
                            onInput={(e) => onInputHandler(dayIndex, exerciseIndex, e.target.name, e.target.value)} />
                    </div>
                    <div className="col-8 col-lg-10">
                        <Input name="noteEsercizio"
                            title="Note"
                            placeholder="Inserisci note"
                            value={exercise.noteEsercizio}
                            error={errors[`days.${dayIndex}.exercises.${exerciseIndex}.noteEsercizio`] ?? null}
                            onInput={(e) => onInputHandler(dayIndex, exerciseIndex, e.target.name, e.target.value)} />
                    </div>
                    {/* Todo questo campo per ora non gestisco e lo salvo statico a true */}
                    {/* <div className="col-4 col-lg-2 d-flex align-items-end">
                        <input
                            type="checkbox"
                            name="isGroupable"
                            className="toggle-checkbox"
                        />
                    </div> */}
                </div>
            </div>
        </div>
    )
}

export default FormEsercizioScheda
