import { Modal, Form } from 'react-bootstrap';
import { Input, Select } from './FormComponents';
import AppButton from './AppButton';

const ExerciseFormModal = ({ show, isEditing, formData, formErrors, setFormData, loading, muscleGroups = [], onClose, onSubmit }) => {
    return (
        <Modal show={show} onHide={onClose} centered size="lg">
            <Modal.Header closeButton>
                <Modal.Title>
                    {isEditing ? 'Modifica Esercizio' : 'Nuovo Esercizio'}
                </Modal.Title>
            </Modal.Header>
            <Form onSubmit={onSubmit}>
                <Modal.Body>
                    <Input
                        name="name"
                        title="Nome"
                        required
                        placeholder="Inserisci il nome dell'esercizio"
                        value={formData.name}
                        onInput={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                        error={formErrors.name}
                    />
                    <Select
                        name="muscle_group_id"
                        title="Gruppo Muscolare"
                        required
                        options={muscleGroups.map(g => ({ value: g.value, name: g.label }))}
                        value={formData.muscle_group_id}
                        onInput={(e) => setFormData(prev => ({ ...prev, muscle_group_id: e.target.value }))}
                        error={formErrors.muscle_group_id}
                    />
                    <Input
                        name="video_execution"
                        title="Video Esecuzione (URL)"
                        type="url"
                        placeholder="https://www.youtube.com/watch?v=..."
                        value={formData.video_execution}
                        onInput={(e) => setFormData(prev => ({ ...prev, video_execution: e.target.value }))}
                        error={formErrors.video_execution}
                    />
                </Modal.Body>
                <Modal.Footer>
                    <AppButton variant="outline-secondary" onClick={onClose}>
                        Annulla
                    </AppButton>
                    <AppButton variant="primary" type="submit" disabled={loading}
                        icon={loading ? 'fas fa-spinner fa-spin' : isEditing ? 'fas fa-pen' : 'fas fa-plus'}
                    >
                        {loading ? 'Salvataggio...' : isEditing ? 'Aggiorna' : 'Crea'}
                    </AppButton>
                </Modal.Footer>
            </Form>
        </Modal>
    );
};

export default ExerciseFormModal;
