const AppButton = ({
    children,
    variant = 'primary',
    type = 'button',
    icon,
    iconPosition = 'left',
    className = '',
    disabled = false,
    onClick,
}) => {
    const hasText = !!children;
    return (
        <button
            type={type}
            className={`btn btn-${variant}${className ? ` ${className}` : ''}`}
            disabled={disabled}
            onClick={onClick}
        >
            {icon && iconPosition === 'left' && <i className={`${icon}${hasText ? ' me-2' : ''}`} />}
            {children}
            {icon && iconPosition === 'right' && <i className={`${icon}${hasText ? ' ms-2' : ''}`} />}
        </button>
    );
};

export default AppButton;
