import React from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

/**
 * Middleware/Guard per proteggere le rotte admin
 * Usa Redux tramite il custom hook useAuth per verificare l'autorizzazione
 */
const AdminRoute = () => {
    const { isAuthenticated, canAccessAdmin } = useAuth();

    // Prima verifica se l'utente è autenticato
    if (!isAuthenticated) {
        return <Navigate to="/login" replace />;
    }

    // Poi verifica se l'utente può accedere alle risorse admin
    if (!canAccessAdmin) {
        return <Navigate to="/workouts/last" replace />;
    }

    // Se passa tutti i controlli, renderizza le rotte figlie
    return <Outlet />;
};

export default AdminRoute;
