import React, { useState, useEffect } from 'react';
import BaseLayout from '../components/BaseLayout';
import { Accordion, Card, Col, Modal } from 'react-bootstrap';
import CardEsercizio from '../components/CardEsercizio/Index';
import TimerModal from '../components/TimerModal';
import { useNavigate, useParams } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { clearErrors, fetchWorkout, lastScheda, saveUpdatedNote, createDaySession, updateNote, updateSession } from '../features/workout/workoutSlice';
import { toast } from 'react-toastify';
import { SchedaService } from '../services/scheda.service';
import { hideLoader, showLoader } from '../features/loader/loaderSlice';
import AllenamentoHeader from '../components/AllenamentoHeader';
import { useMemo } from 'react';

const Allenamento = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const { id = null, day } = useParams();
    const { workout, sessions, latestWorkoutId, errors } = useSelector(state => state.workout);
    const dayWorkout = workout.esercizi_x_day?.[day] || [];
    const [daySessions, setDaySessions] = useState({});

    const [currentVideo, setCurrentVideo] = useState(null);
    const [isLatest, setIsLatest] = useState(false);
    const [timer, setTimer] = useState({ isVisible: false, seconds: 60 });
    const [startedSessionInfo, setStartedSessionInfo] = useState(null);

    // Funzione chiamata ogni volta che cambia il testo nella casella di ricerca
    const handleChangeNote = (day, exerciseId, value) => {
        dispatch(updateNote({ day, exerciseId, value }));
    };

    const saveChangedNote = (exerciseId, value) => {
        // Alla perdita del focus, invio il valore ottenuto al backend
        dispatch(saveUpdatedNote({ exerciseId, value, isLatest }));
    }

    const startSession = async () => {
        const now = new Date();
        const requestData = {
            day,
            // Formatta data e ora in formato stringa
            session_date: now.toISOString().split('T')[0], // yyyy-mm-dd
            start_time: now.toTimeString().split(' ')[0] // HH:MM:SS
        }

        try {
            dispatch(showLoader());
            const { data } = await SchedaService.startSession({ workoutId: workout.idScheda, data: requestData });
            toast.success(data.message);
            // Vado ad inserire la sessione creata nello state redux
            dispatch(createDaySession({ day, sessions: data.data?.session_exercises || [], isLatest }));

            if (!!data.data?.session_info) {
                const session_info = { ...data.data.session_info, day, active: true };
                setStartedSessionInfo(session_info);
                localStorage.setItem('session_started', JSON.stringify(session_info));
            }
        } catch (error) {
            console.error("Errore nel salvataggio:", error);
        } finally {
            dispatch(hideLoader());
        }
    };

    const stopSession = async () => {
        const now = new Date();
        const requestData = {
            session_id: startedSessionInfo.id,
            day,
            end_time: now.toTimeString().split(' ')[0] // HH:MM:SS
        }

        try {
            dispatch(showLoader());
            const { data } = await SchedaService.stopSession({ workoutId: workout.idScheda, data: requestData });

            toast.success(data.message);
            setStartedSessionInfo(null);
            localStorage.removeItem('session_started');
        } catch (error) {
            console.error("Errore nel salvataggio:", error);
        } finally {
            dispatch(hideLoader());
        }
    }

    // Aggiornamento del gruppo sessioni passate...
    const handleChangeSessions = (field, exerciseId, sessionId, index, value) => {
        setDaySessions(prev => {
            const prevSessions = { ...prev }; // copia dell'oggetto
            const exerciseSessions = [...(prevSessions[exerciseId] || [])]; // copia l'array delle sessioni per l'esercizio specifico
            const sessionIndex = exerciseSessions.findIndex(s => s.session_id === sessionId);
            const session = { ...exerciseSessions[sessionIndex] }; // copia l'intero oggetto session selezionato
            const fieldArray = [...session[field]]; // copia array interno

            fieldArray[index] = value; // aggiorno il valore

            session[field] = fieldArray; // aggiorno la chiave field
            exerciseSessions[sessionIndex] = session; // aggiorno il session modificato

            prevSessions[exerciseId] = exerciseSessions;

            return prevSessions; // ritorno l'oggetto aggiornato
        });
    };

    // Aggiornamento del gruppo sessioni passate...
    // Aggiunge una riga peso|reps all'item sessione
    const handleAddRow = (exerciseId, maxSets, sessionId) => {
        const sessionIndex = daySessions?.[exerciseId]?.findIndex(s => s.session_id === sessionId);
        // Esco se non trovo l'esercizio o la sessione
        if (!sessionIndex || sessionIndex < 0) return;

        if (daySessions[exerciseId][sessionIndex].weights.length < maxSets) {
            setDaySessions(prev => {
                const prevSessions = { ...prev }; // copia dell'oggetto
                const exerciseSessions = [...(prevSessions[exerciseId] || [])]; // copia l'array delle sessioni per l'esercizio specifico
                const session = { ...exerciseSessions[sessionIndex] }; // copia l'intero oggetto session selezionato

                const weights = [...session.weights];
                const lastWeights = weights[weights.length - 1];
                // aggiungo un item in coda all'array "weights"
                weights.push(lastWeights);

                const reps = [...session.reps];
                const lastReps = reps[reps.length - 1];
                // aggiungo un item in coda all'array "reps"
                reps.push(lastReps);

                exerciseSessions[sessionIndex] = { ...session, weights, reps }; // aggiorno la session modificato
                prevSessions[exerciseId] = exerciseSessions;

                return prevSessions; // ritorno l'oggetto aggiornato
            });
        }
    };

    // Salvo i sets dell'esercizio nel database. Se si tratta dell'ultima scheda, aggiorno pure le sessioni nel localStorage (isLatest)
    const saveSessionItem = async (exercise = {}, sessionData = {}) => {
        const requestData = {
            exercise_id: sessionData.protocol_exercise_id,
            original_exercise_id: sessionData.exercise_id,
            weights: [...sessionData.weights],
            reps: [...sessionData.reps],
            is_completed: sessionData.is_completed || false
        }

        try {
            dispatch(showLoader());
            const { data } = await SchedaService.saveSession({ workoutId: workout.idScheda, sessionId: sessionData.session_id, data: requestData });
            toast.success(data.message);

            dispatch(updateSession({
                day: exercise.giornoEsecuzione,
                muscleGroup: exercise.gruppoMuscolare,
                exerciseId: sessionData.protocol_exercise_id,
                updatedSession: data.data,
                // Se si tratta dell'ultimo workout per l'atleta, aggiorno l'istanza presente nel localstorage
                isLatest: isLatest
            }));
        } catch (error) {
            console.error("Errore nel salvataggio:", error);
        } finally {
            dispatch(hideLoader());
        }
    }

    useEffect(() => {
        if (!!id) {
            if (!!workout.idScheda && workout.idScheda == id) return;

            dispatch(fetchWorkout(id));
        } else {
            setIsLatest(true);
            if (!!workout.idScheda && workout.idScheda === latestWorkoutId) return;

            dispatch(lastScheda());
        }
    }, [dispatch, id]);

    useEffect(() => {
        // console.log('workout', workout)
        // console.log('day', day)

        if (!!workout.esercizi_x_day && !workout.esercizi_x_day[day]) {
            // Reindirizza alla pagina di errore
            navigate("/error", {
                state: {
                    code: 404,
                    message: "Allenamento non trovato.",
                    cta: {
                        description: "Clicca per ritornare alla scheda",
                        actionLabel: "Ritorna",
                        route: `/workouts/${workout.idScheda}`
                    }
                }
            });
        }

        try {
            const sessionInfo = JSON.parse(localStorage.getItem('session_started'));
            if (workout.idScheda === sessionInfo.protocol_id && day === sessionInfo.day) {
                setStartedSessionInfo(sessionInfo);
            }
        } catch (error) { }
    }, [workout, day]);

    useEffect(() => {
        if (!!Object.keys(errors).length) {
            const { status_code: code, message, info, cta, redirect_link } = errors;
            // resetto l'oggetto errors..
            dispatch(clearErrors());

            if (redirect_link) {
                navigate(redirect_link);
            } else {
                // Reindirizza alla pagina di errore
                navigate("/error", {
                    state: {
                        code,
                        message,
                        cta: {
                            description: info || null,
                            actionLabel: cta?.label || "Ritorna alla home",
                            route: cta?.action || "/workouts/last"
                        }
                    }
                });
            }
        }
    }, [errors]);

    /**
     * Prendo l'array delle sessioni dallo state globale, 
     * recupero solo quelle del giorno selezionato 
     * e lo rimappo a mio piacimento
     */
    useEffect(() => {
        // Esco se prima non è stato inizializzato il globalState delle sessioni
        if (!Object.keys(sessions).length) return;

        const tempData = sessions?.[day] || []
        // Rimappo l'oggetto sessioni raggruppando per ogni esercizio del protocollo
        const groupedByProtocolExercise = tempData.reduce((acc, session) => {
            const { protocol_exercise_id } = session;

            if (!acc[protocol_exercise_id]) {
                acc[protocol_exercise_id] = [];
            }

            acc[protocol_exercise_id].push(session);
            return acc;
        }, {});

        // Salvo nello state locale, faccio prima un aggiornamento locale, poi aggiorno lo state globale
        setDaySessions(groupedByProtocolExercise)
        // console.log('tutte le sessioni per questo giorno', groupedByProtocolExercise)
    }, [sessions])

    const progressInfo = useMemo(() => {
        if (!startedSessionInfo) return { countExercisesCompleted: 0, completionPercentage: 0 };

        const startedSession = Object.values(daySessions).flatMap(exerciseSessions => exerciseSessions.filter(session => session.session_id === startedSessionInfo.id));
        // Sessione corrente per ogni esercizio
        // console.log('final map', startedSession)

        const countExercisesCompleted = startedSession.filter(session => session.is_completed).length;
        // console.log('Esercizi completati oggi:', countExercisesCompleted);

        // Mi ricavo la percentuale di completamento
        const completionPercentage = Math.round((countExercisesCompleted / dayWorkout.length) * 100);

        return {
            countExercisesCompleted,
            completionPercentage
        };
    }, [daySessions]);

    if (!workout.idScheda) return <></>;
    return (
        <BaseLayout>
            <section className="allenamento-page">
                <AllenamentoHeader
                    workoutTitle={workout.nomeScheda}
                    completionPercentage={progressInfo.completionPercentage}
                    totalExercises={dayWorkout.length}
                    completedCount={progressInfo.countExercisesCompleted}
                    {...{ day, startedSessionInfo, startSession, stopSession }} />
                <Accordion defaultActiveKey={[0]} className="accordion-allenamento" alwaysOpen>
                    {dayWorkout.map((esercizio, index) => (
                        <Accordion.Item eventKey={index} key={index}>
                            <Accordion.Button>
                                <div className="d-flex align-items-center gap-2">
                                    <div className="health-icon">
                                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                            <path d="M22 12h-2.48a2 2 0 0 0-1.93 1.46l-2.35 8.36a.25.25 0 0 1-.48 0L9.24 2.18a.25.25 0 0 0-.48 0l-2.35 8.36A2 2 0 0 1 4.49 12H2"></path>
                                        </svg>
                                    </div>
                                    <div>
                                        <h3 className="exercise-title">{esercizio.nome}</h3>
                                        <span className="badge badge-secondary">{esercizio.gruppoMuscolare}</span>
                                    </div>
                                </div>
                            </Accordion.Button>

                            <Accordion.Collapse eventKey={index}>
                                <CardEsercizio
                                    saveSessionItemCb={saveSessionItem}
                                    esercizio={esercizio}
                                    exerciseSessions={daySessions?.[esercizio.id] || []}
                                    handleChangeSessions={handleChangeSessions}
                                    handleAddRow={handleAddRow}
                                    setCurrentVideo={setCurrentVideo}
                                    handleChangeNote={(e) => handleChangeNote(day, esercizio.id, e.target.value)}
                                    saveChangedNote={(e) => saveChangedNote(esercizio.id, e.target.value)}
                                    setTimer={setTimer}
                                    startedSessionInfo={startedSessionInfo} />
                            </Accordion.Collapse>
                        </Accordion.Item>
                    ))}
                </Accordion>
            </section>

            {/* Modal per la visualizzazione del video embed youtube */}
            <Modal show={!!currentVideo} onHide={() => setCurrentVideo(null)} centered>
                <Modal.Header closeButton>
                </Modal.Header>
                <Modal.Body>
                    <iframe
                        title={currentVideo}
                        className="video-wrapper w-100"
                        style={{ minHeight: '250px' }}
                        src={currentVideo}
                        frameBorder="0"
                        allowFullScreen
                    ></iframe>
                </Modal.Body>
            </Modal>

            <TimerModal
                show={timer.isVisible}
                // Resetto il timer alla chiusura della modale
                onHide={() => setTimer(prev => ({ ...prev, isVisible: false, seconds: 60 }))}
                initialTime={timer.seconds}
            />
        </BaseLayout>
    )
}

export default Allenamento
