import { SchedaService } from "../services/scheda.service";

export const saveToLocalStorage = store => next => action => {
    const result = next(action);
    const isLatest = action.payload?.isLatest;

    // Salva solo se la scheda è la più recente
    // Viene salvata nello stesso formato come è stata ricevuta inizialmente dall'API
    if (isLatest) {
        console.log('Sincronizzo il workout nel localStorage...')
        const { workout, sessions: sessioni } = store.getState().workout;
        SchedaService.setScheda({ ...workout, sessioni });
    }

    return result;
};
