import React, { useEffect, useState } from 'react'
import { Link, useLocation } from 'react-router-dom';
import styles from "./ErrorPage.module.css";

const ErrorPage = () => {
    const location = useLocation();
    const [codeString, setCodeString] = useState("");
    const { message = "Pagina non trovata!", code = 404, cta = { description: null, actionLabel: "Ritorna alla home", route: "/workouts/last" } } = location.state || {}


    useEffect(() => {
        setCodeString(code.toString());
    }, [code]);

    return (
        <div className={styles.errorContainer}>
            <h1 className={styles.errorCode}>
                {codeString[0]}<span><i className="fas fa-ghost"></i></span>{codeString[2]}
            </h1>
            <h2>{message}</h2>
            {!!cta.description && (
                <p>{cta.description}</p>
            )}
            <Link className="btn btn-primary" to={cta.route}>{cta.actionLabel}</Link>
        </div>
    );
}

export default ErrorPage;
