import React from 'react'
import { Link, useLocation } from 'react-router-dom'
import { useSelector } from 'react-redux'
import { getUserInitials } from '../functions'

const Navbar = ({ onToggleSidebar }) => {
    const { user } = useSelector(state => state.user);
    const location = useLocation();

    const isActive = (path) => {
        if (path === '/workouts/last') {
            // "Scheda" è attivo solo per /workouts/last o /workouts/last/*
            return location.pathname === '/workouts/last' || location.pathname.startsWith('/workouts/last/');
        }
        if (path === '/workouts') {
            // "I miei Workout" è attivo per /workouts ma NON per /workouts/last
            return location.pathname.startsWith('/workouts') && !location.pathname.startsWith('/workouts/last');
        }
        if (path === '/progress') {
            return location.pathname.startsWith('/progress');
        }
        return location.pathname === path;
    };

    return (
        <nav className="app-navbar">
            <div className="navbar-container">
                <div className="navbar-links">
                    <Link className={`navbar-link ${isActive('/workouts/last') ? 'active' : ''}`} to="/workouts/last"><i className="fa-solid fa-dumbbell"></i><span>Scheda</span></Link>
                    <Link className={`navbar-link ${isActive('/progress') ? 'active' : ''}`} to="/progress"><i className="fa-solid fa-chart-line"></i><span>Progressi</span></Link>
                </div>

                <button
                    className="navbar-user-avatar"
                    onClick={onToggleSidebar}
                    aria-label="Apri menu"
                >
                    {user?.avatar_url ? (
                        <img
                            src={user.avatar_url}
                            alt="Avatar"
                            className="navbar-user-avatar-img"
                        />
                    ) : (
                        <div className="navbar-user-avatar-placeholder">
                            {getUserInitials(user)}
                        </div>
                    )}
                </button>
            </div>
        </nav>
    )
}

export default Navbar
