import React, { useEffect, useState } from 'react';
import { Modal, Button, Accordion } from 'react-bootstrap';
import FormEsercizioScheda from '../components/FormEsercizioScheda';
import { Input } from '../components/FormComponents';
import BaseLayout from '../components/BaseLayout';
import { SchedaService } from '../services/scheda.service';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useSelector } from 'react-redux';

const SchedaCreate = () => {
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const { user } = useSelector(state => state.user);
    const [showWelcomeModal, setShowWelcomeModal] = useState(false);

    const objEsercizio = {
        giornoEsecuzione: 1,
        nomeEsercizio: null,
        fkEsercizio: null,
        numeroRipetizioni: "",
        serieTotali: "",
        recuperoXserie: "",
        noteEsercizio: "",
        isGroupable: true
    }

    const baseFormData = [
        {
            day: 1,
            exercises: [
                {
                    ...objEsercizio
                }
            ]
        }
    ];

    const [scheda, setScheda] = useState({
        nomeScheda: "",
        numeroAllSettimanali: "",
        dataDiScadenza: "",
        fkUtente: user?.idUtente // Uso l'ID dell'utente dallo state
    });
    const [days, setDays] = useState(baseFormData);
    const [accordions, setAccordions] = useState({ 0: true });
    const [errors, setErrors] = useState({});
    const [showModal, setShowModal] = useState(false);

    const onInputScheda = (e) => {
        const { name, value } = e.target;

        setScheda((prev) => ({ ...prev, [name]: value }));
    }

    const onInputEsercizio = (dayIndex, exerciseIndex, property, newValue) => {
        setDays((prevDays) => {
            const newDays = [...prevDays];
            // Copia dell'array exercises
            const newExercises = [...newDays[dayIndex].exercises];
            newExercises[exerciseIndex] = {
                ...newExercises[exerciseIndex],
                [property]: newValue
            }

            newDays[dayIndex] = {
                ...newDays[dayIndex],
                exercises: newExercises
            }

            return newDays;
        });
    };

    const handleAddExercise = (dayIndex) => {
        const origDays = [...days];
        const day = origDays[dayIndex].day;
        origDays[dayIndex].exercises.push({ ...objEsercizio, giornoEsecuzione: day }); // creo un oggetto esercizio vuoto
        setDays(origDays);
    };

    const handleAddDay = () => {
        const nextDay = days.length + 1;

        setDays((prevDays) => [...prevDays, { day: nextDay, exercises: [{ ...objEsercizio, giornoEsecuzione: nextDay }] }]);
        setAccordions((prev) => ({ ...prev, [days.length]: true }));
    };

    const removeEsercizio = (dayIndex, exerciseIndex) => {
        setDays((prev) => {
            const newDays = [...prev];
            // Copia dell'array exercises
            const newExercises = [...newDays[dayIndex].exercises];
            // Rimuovo l'elemento all'indice selezionato
            newExercises.splice(exerciseIndex, 1);

            newDays[dayIndex] = {
                ...newDays[dayIndex],
                exercises: newExercises
            }

            return newDays;
        });
    }

    const handleToggleAccordion = (dayIndex) => setAccordions((prev) => ({ ...prev, [dayIndex]: !prev[dayIndex] }));
    const handleModalClose = () => setShowModal(false);
    const handleModalShow = () => setShowModal(true);

    const handleSaveScheda = async (e) => {
        e.preventDefault();

        const data = {
            ...scheda,
            days
        }

        try {
            const { data: result } = await SchedaService.createScheda(data);
            setErrors({}); // Resetto l'oggetto errori
            // Redirect alla pagina della scheda appena creata
            toast.success(result.message, {
                onClose: () => {
                    navigate(`/workouts/${result.data.idScheda}`);
                },
                onClick: () => {
                    navigate(`/workouts/${result.data.idScheda}`);
                }
            });
        } catch (error) {
            if (error.response && error.response.data) {
                // Gestione errori di validazione
                setErrors(error.response.data.errors || {});
            } else {
                // Gestione altri errori
                toast.error('Si è verificato un errore durante il salvataggio della scheda');
            }
        }
    }

    const closeWelcomeModal = () => setShowWelcomeModal(false)

    useEffect(() => {
        // Controlla se è presente il parametro welcome
        if (searchParams.get('welcome') === 'true') {
            setShowWelcomeModal(true);
        }

    }, [searchParams, setSearchParams]);

    return (
        <BaseLayout>
            <div className="page-content">
                <div className="page-header">
                    <h1 className="page-header__title">Crea la tua scheda</h1>
                    <p className="page-header__subtitle">Definisci il tuo piano di allenamento personalizzato</p>
                </div>

                <form className="form-create-scheda">
                    {/* Form info scheda */}
                    <div className="row mb-4">
                        <div className="col-12">
                            <h3>Info scheda</h3>
                        </div>
                        <div className="col-12 col-lg-7 mb-2">
                            <Input required name='nomeScheda'
                                title='Nome Scheda'
                                placeholder="Inserisci nome scheda"
                                value={scheda.nomeScheda}
                                onInput={onInputScheda}
                                error={errors.nomeScheda} />
                        </div>
                        <div className="col-6 col-lg-3 mb-2">
                            <Input required type="number"
                                name='numeroAllSettimanali'
                                title='Allenamenti settimanali'
                                placeholder="Inserisci numero allenamenti settimanali"
                                value={scheda.numeroAllSettimanali}
                                onInput={onInputScheda}
                                error={errors.numeroAllSettimanali} />
                        </div>
                        <div className="col-6 col-lg-2 mb-2">
                            <Input required type="date"
                                name='dataDiScadenza'
                                title='Scadenza'
                                placeholder="Data di scadenza"
                                value={scheda.dataDiScadenza}
                                onInput={onInputScheda}
                                error={errors.dataDiScadenza} />
                        </div>
                    </div>

                    {/* Form accordions esercizi */}
                    {
                        days.map((day, dayIndex) => (
                            <Accordion key={day.day} defaultActiveKey="0" className="mb-4">
                                <Accordion.Item eventKey="0">
                                    {/* Header Personalizzato */}
                                    <div className="card my-accordion-header">
                                        <div className="d-flex justify-content-between">
                                            <div className="box my-accordion-header-child">Allenamento {day.day}</div>

                                            {/* Button per togglare l'apertura dell'accordion */}
                                            <button
                                                className="box my-accordion-header-btn my-accordion-header-child"
                                                onClick={() => handleToggleAccordion(dayIndex)}
                                                aria-expanded={accordions[dayIndex]}
                                                type="button"
                                            >
                                            </button>
                                        </div>
                                    </div>

                                    {/* .form-gruppo-esercizi */}
                                    <Accordion.Collapse eventKey="0" className="form-gruppo-esercizi row gy-2 mt-2 mb-4" in={accordions[dayIndex]}>
                                        <>
                                            <p className="text-secondary m-0">
                                                Compila gli esercizi per il giorno corrente. Nota bene, l'ordine di inserimento determina l'ordine di visualizzazione.
                                            </p>
                                            {
                                                day.exercises.map((exercise, i) => (
                                                    <FormEsercizioScheda key={i}  {...{ dayIndex, exercise, setDays, removeEsercizio, errors }} exerciseIndex={i} onInputHandler={onInputEsercizio} />
                                                ))
                                            }

                                            <div>
                                                <Button
                                                    variant='add-form'
                                                    onClick={() => handleAddExercise(dayIndex)}
                                                    className="mt-2"
                                                >Aggiungi esercizio
                                                </Button>
                                            </div>
                                        </>
                                    </Accordion.Collapse>
                                </Accordion.Item>
                            </Accordion>
                        ))
                    }

                    <Button variant="add-form" onClick={handleAddDay} className="mb-3">
                        Aggiungi giorno
                    </Button>
                    <div className="text-end">
                        <Button variant="primary" onClick={handleSaveScheda}>
                            Salva
                        </Button>
                    </div>
                </form>
            </div>

            {/* <Modal show={showModal} onHide={handleModalClose}>
          <Modal.Header closeButton>
            <Modal.Title>Crea esercizio</Modal.Title>
          </Modal.Header>
          <Modal.Body>
            <p>Compila il form sottostante. L'esercizio creato sarà aggiunto automaticamente alla tua scheda.</p>
            <div className="mb-3">
              <label>Nome esercizio</label>
              <input
                className="form-control my-form-control"
                type="text"
                name="esercizio"
                placeholder="Inserisci un nome per l'esercizio che vuoi creare"
              />
            </div>
            <div>
              <label>Gruppo muscolare</label>
              <select className="form-select my-form-control" name="gruppoMuscolare">
                <option value="1">Gruppo 1</option>
                <option value="2">Gruppo 2</option>
              </select>
            </div>
            <p className="text-info-message mt-3">
              Attenzione, l'esercizio sarà visibile a tutti gli utenti, si prega di inserire dati pertinenti.
            </p>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={handleModalClose}>
              Chiudi
            </Button>
            <Button variant="primary" onClick={() => { }}>
              Crea
            </Button>
          </Modal.Footer>
        </Modal> */}

            {/* Modale di atterraggio per i nuovi iscritti */}
            <Modal
                show={showWelcomeModal}
                onHide={closeWelcomeModal}
                centered
                size="xl"
                className="welcome-modal"
            >
                <Modal.Header closeButton className="welcome-modal__header">
                    <div>
                        <Modal.Title as="h2" className="welcome-modal__title m-0">
                            Benvenuto su Train UP
                        </Modal.Title>
                        <p className="welcome-modal__subtitle">
                            Pianifica, traccia e ottimizza ogni sessione grazie al tuo nuovo coach digitale.
                        </p>
                    </div>
                </Modal.Header>
                <Modal.Body className="welcome-modal__body">
                    <section className="welcome-modal__hero">
                        <div>
                            <h3 className="welcome-modal__hero-title">Costruisci il tuo primo piano settimanale</h3>
                            <p className="welcome-modal__hero-text">
                                In pochi minuti puoi creare una scheda giorno per giorno, duplicare le routine efficaci e lasciare che l'app trasformi i tuoi dati in insight immediati.
                            </p>
                            <div className="welcome-modal__chips">
                                <span className="welcome-modal__chip">Scheduler intelligente</span>
                                <span className="welcome-modal__chip">Tracking avanzato</span>
                                <span className="welcome-modal__chip">Report motivanti</span>
                            </div>
                        </div>
                    </section>

                    <section className="welcome-modal__highlight-section">
                        <h6 className="welcome-modal__section-title">Sfrutta tutto il potenziale della piattaforma</h6>
                        <div className="welcome-modal__highlight-grid">
                            <article className="welcome-modal__highlight-card">
                                <i className="fas fa-diagram-project welcome-modal__highlight-icon"></i>
                                <h5>Programmazione smart</h5>
                                <p>Distribuisci allenamenti, gruppi muscolari e intensità con blocchi modulari e riutilizzabili.</p>
                            </article>
                            <article className="welcome-modal__highlight-card">
                                <i className="fas fa-chart-line welcome-modal__highlight-icon"></i>
                                <h5>Analisi dei progressi</h5>
                                <p>Traccia serie, ripetizioni, RPE e note: Train UP confronta automaticamente le sessioni e mette in evidenza i trend.</p>
                            </article>
                            <article className="welcome-modal__highlight-card">
                                <i className="fas fa-handshake welcome-modal__highlight-icon"></i>
                                <h5>Supporto continuo</h5>
                                <p>Ricevi promemoria di scadenza scheda, suggerimenti di progressione e uno spazio condiviso con il tuo coach.</p>
                            </article>
                        </div>
                    </section>

                    <section className="welcome-modal__steps">
                        <h6 className="welcome-modal__section-title">Come iniziare</h6>
                        <div className="welcome-modal__step">
                            <span className="welcome-modal__step-index">1</span>
                            <div>
                                <h5>Definisci i giorni</h5>
                                <p>Imposta quante volte vuoi allenarti e assegna un focus a ogni giornata.</p>
                            </div>
                        </div>
                        <div className="welcome-modal__step">
                            <span className="welcome-modal__step-index">2</span>
                            <div>
                                <h5>Aggiungi gli esercizi</h5>
                                <p>Personalizza serie, recuperi e note per creare routine che parlano il tuo linguaggio.</p>
                            </div>
                        </div>
                        <div className="welcome-modal__step">
                            <span className="welcome-modal__step-index">3</span>
                            <div>
                                <h5>Monitora e adatta</h5>
                                <p>Salva la scheda, registra le sessioni e lascia che i report ti suggeriscano i prossimi step.</p>
                            </div>
                        </div>
                    </section>

                    <div className="welcome-modal__tip">
                        <i className="fas fa-lightbulb me-2"></i>
                        <p className="mb-0">
                            Consiglio: parti da un allenamento essenziale e duplica i giorni che funzionano per costruire blocchi settimanali più lunghi.
                        </p>
                    </div>
                </Modal.Body>
                <Modal.Footer className="welcome-modal__footer">
                    <Button
                        type="button"
                        variant="primary"
                        className="welcome-modal__cta"
                        onClick={closeWelcomeModal}
                    >
                        <i className="fas fa-play me-2"></i>
                        Inizia a creare
                    </Button>
                </Modal.Footer>
            </Modal>
        </BaseLayout>
    );
}

export default SchedaCreate;
