import React from 'react';

const ProgressStats = ({ exercisesWithDataByDay }) => {
    console.log(Object.values(exercisesWithDataByDay));
    const totalExercises = Object.values(exercisesWithDataByDay).flat().length;
    const totalDays = Object.keys(exercisesWithDataByDay).length;
    const totalSessions = Object.values(exercisesWithDataByDay)
        .flat()
        .reduce((sum, ex) => sum + (ex.sessionCount || 0), 0);

    const stats = [
        { label: 'Esercizi', value: totalExercises, icon: 'fa-dumbbell', color: '#AFDE1F' },
        { label: 'Giorni', value: totalDays, icon: 'fa-calendar-days', color: '#FF8C42' },
        { label: 'Sessioni', value: totalSessions, icon: 'fa-chart-line', color: '#AFDE1F' }
    ];

    return (
        <div className="progress-stats-overview">
            {stats.map((stat, index) => (
                <div key={index} className="stat-card">
                    <div className="stat-icon" style={{ backgroundColor: `${stat.color}15`, color: stat.color }}>
                        <i className={`fas ${stat.icon}`}></i>
                    </div>
                    <div className="stat-content">
                        <div className="stat-value">{stat.value}</div>
                        <div className="stat-label">{stat.label}</div>
                    </div>
                </div>
            ))}
        </div>
    );
};

export default ProgressStats;
